{
  "name": "PharmaMind - Smart Pharmacy Assistant",
  "description": "An offline-first commercial web application for calculating drug discounts, analyzing purchase history, and managing invoices with intelligent insights."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ItemType {
  NORMAL = 'عادي',
  SPECIAL = 'خاص',
  OTHER = 'أخرى',
}

export enum TaxMethod {
  PER_UNIT = 'لكل وحدة',
  TOTAL = 'إجمالي',
}

export interface AppSettings {
  discountNormal: number;
  discountSpecial: number;
  discountOther: number;
  pharmacyName: string;
}

export interface ItemInput {
  id: string;
  name: string;
  type: ItemType;
  qty: number;
  bonus: number;
  publicPrice: number;
  pharmaPrice: number;
  supplierDiscountVal: number;
  extraDiscountPct: number;
  taxValue: number;
  taxMethod: TaxMethod;
}

export interface CalculatedItem extends ItemInput {
  totalUnits: number;
  baseTotal: number; // pharmaPrice * qty
  typeDiscountValue: number;
  afterTypeDiscount: number;
  extraDiscountValue: number;
  taxTotal: number;
  netTotalCost: number; // The final bill amount for this line
  netUnitCost: number; // netTotalCost / totalUnits
  realDiscountPct: number; // 1 - (netUnitCost / publicPrice)

  // AI Insights
  historyComparison?: 'better' | 'worse' | 'same' | 'new';
  priceDifferencePct?: number;
  savingsVsHistory?: number;
  isFakeDiscount?: boolean;
}

export interface Invoice {
  id: string;
  date: string; // ISO String
  items: CalculatedItem[];
  totalValue: number;
  totalItems: number;
  totalUnits: number;
}

export const DEFAULT_SETTINGS: AppSettings = {
  discountNormal: 20,
  discountSpecial: 10,
  discountOther: 0,
  pharmacyName: 'صيدليتي الذكية'
};

import { AppSettings, DEFAULT_SETTINGS, Invoice, CalculatedItem } from '../types';

const KEYS = {
  SETTINGS: 'pharmamind_settings',
  INVOICES: 'pharmamind_invoices',
};

export const StorageService = {
  // Settings
  getSettings: (): AppSettings => {
    try {
      const data = localStorage.getItem(KEYS.SETTINGS);
      return data ? JSON.parse(data) : DEFAULT_SETTINGS;
    } catch (e) {
      return DEFAULT_SETTINGS;
    }
  },

  saveSettings: (settings: AppSettings): void => {
    localStorage.setItem(KEYS.SETTINGS, JSON.stringify(settings));
  },

  // Invoices
  getInvoices: (): Invoice[] => {
    try {
      const data = localStorage.getItem(KEYS.INVOICES);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      return [];
    }
  },

  saveInvoice: (invoice: Invoice): void => {
    const invoices = StorageService.getInvoices();
    // Prepend to show newest first
    const updated = [invoice, ...invoices];
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(updated));
  },

  deleteInvoice: (id: string): void => {
    const invoices = StorageService.getInvoices();
    const updated = invoices.filter(inv => inv.id !== id);
    localStorage.setItem(KEYS.INVOICES, JSON.stringify(updated));
  },

  // AI Helper: Get last purchase of an item
  getLastPurchaseItem: (itemName: string): CalculatedItem | null => {
    const invoices = StorageService.getInvoices();
    for (const inv of invoices) {
      const found = inv.items.find(item => item.name.trim().toLowerCase() === itemName.trim().toLowerCase());
      if (found) return found;
    }
    return null;
  }
};

import { ItemInput, CalculatedItem, AppSettings, TaxMethod, ItemType } from '../types';
import { StorageService } from './storageService';

export const CalculatorService = {
  calculateItem: (input: ItemInput, settings: AppSettings): CalculatedItem => {
    const {
      type,
      pharmaPrice,
      qty,
      bonus,
      supplierDiscountVal,
      extraDiscountPct,
      taxValue,
      taxMethod,
      publicPrice
    } = input;

    // 1. Base Discount % based on Type Settings
    let typeDiscountPct = 0;
    switch (type) {
      case ItemType.NORMAL: typeDiscountPct = settings.discountNormal / 100; break;
      case ItemType.SPECIAL: typeDiscountPct = settings.discountSpecial / 100; break;
      case ItemType.OTHER: typeDiscountPct = settings.discountOther / 100; break;
    }

    // 2. Financial Calculations
    const totalUnits = qty + bonus;
    const baseTotal = pharmaPrice * qty; // Cost without any discount

    // Type Discount
    const typeDiscountValue = baseTotal * typeDiscountPct;
    const afterTypeDiscount = baseTotal - typeDiscountValue;

    // Extra Percentage Discount (applied on the remaining amount)
    const extraDiscountValue = afterTypeDiscount * (extraDiscountPct / 100);

    // Subtotal before supplier cash discount and tax
    let subTotal = afterTypeDiscount - extraDiscountValue;

    // Supplier Cash Discount (Flat value deducted)
    subTotal = subTotal - supplierDiscountVal;

    // Tax
    let taxTotal = 0;
    if (taxMethod === TaxMethod.PER_UNIT) {
      taxTotal = taxValue * qty; // Usually tax is paid on purchased qty, sometimes on bonus too. Assuming purchased qty for cost basis.
    } else {
      taxTotal = taxValue;
    }

    // Final Net Cost for the whole line
    const netTotalCost = subTotal + taxTotal;

    // Unit Cost
    const netUnitCost = totalUnits > 0 ? netTotalCost / totalUnits : 0;

    // Real Discount % (Compared to Public Price)
    // Formula: 1 - (Net Unit Cost / Public Price)
    const realDiscountPct = publicPrice > 0 ? (1 - (netUnitCost / publicPrice)) * 100 : 0;

    // 3. AI / Smart Insights
    const result: CalculatedItem = {
      ...input,
      totalUnits,
      baseTotal,
      typeDiscountValue,
      afterTypeDiscount,
      extraDiscountValue,
      taxTotal,
      netTotalCost,
      netUnitCost,
      realDiscountPct,
      historyComparison: 'new',
      isFakeDiscount: false
    };

    // History Comparison
    const lastPurchase = StorageService.getLastPurchaseItem(input.name);
    if (lastPurchase) {
      const diff = netUnitCost - lastPurchase.netUnitCost;
      const pctDiff = lastPurchase.netUnitCost > 0 ? (diff / lastPurchase.netUnitCost) * 100 : 0;

      result.priceDifferencePct = Math.abs(pctDiff);

      if (diff < -0.001) { // Cheaper now
        result.historyComparison = 'better';
        result.savingsVsHistory = Math.abs(diff) * totalUnits;
      } else if (diff > 0.001) { // More expensive
        result.historyComparison = 'worse';
        result.savingsVsHistory = -1 * Math.abs(diff) * totalUnits;
      } else {
        result.historyComparison = 'same';
      }
    }

    // Fake Discount Detection
    // Logic: If declared discount (e.g. 20%) is vastly different from real discount due to price hikes or bad bonus structure.
    // Or simpler: If real discount is negative (cost > public) or suspciously low compared to type discount.
    const expectedTypeDiscount = typeDiscountPct * 100;
    if (realDiscountPct < (expectedTypeDiscount - 5)) {
      result.isFakeDiscount = true; // Flag if real discount is significantly worse than the "base" type discount
    }

    return result;
  }
};

import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  Calculator, 
  FileText, 
  Settings, 
  PieChart, 
  Menu, 
  X,
  Pill
} from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
}

const Layout: React.FC<LayoutProps> = ({ children }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const location = useLocation();

  const navItems = [
    { label: 'لوحة التحكم', path: '/', icon: LayoutDashboard },
    { label: 'حاسبة الفواتير', path: '/calculator', icon: Calculator },
    { label: 'سجل الفواتير', path: '/invoices', icon: FileText },
    { label: 'التقارير الذكية', path: '/reports', icon: PieChart },
    { label: 'الإعدادات', path: '/settings', icon: Settings },
  ];

  const closeSidebar = () => setIsSidebarOpen(false);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col md:flex-row print:bg-white">
      {/* Mobile Header */}
      <div className="bg-primary-600 text-white p-4 flex justify-between items-center md:hidden no-print">
        <h1 className="text-xl font-bold flex items-center gap-2">
          <Pill className="w-6 h-6" /> PharmaMind
        </h1>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
          {isSidebarOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-20 md:hidden no-print"
          onClick={closeSidebar}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 right-0 z-30 w-64 bg-white shadow-xl transform transition-transform duration-300 ease-in-out
        md:relative md:translate-x-0 md:shadow-none border-l border-gray-200 no-print
        ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full md:translate-x-0'}
      `}>
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-gray-100 hidden md:flex items-center gap-3 text-primary-600">
             <Pill className="w-8 h-8" />
             <span className="text-2xl font-bold tracking-tight">PharmaMind</span>
          </div>

          <nav className="flex-1 p-4 space-y-2">
            {navItems.map((item) => {
              const Icon = item.icon;
              const isActive = location.pathname === item.path;
              return (
                <Link
                  key={item.path}
                  to={item.path}
                  onClick={closeSidebar}
                  className={`
                    flex items-center gap-3 px-4 py-3 rounded-xl transition-all
                    ${isActive 
                      ? 'bg-primary-50 text-primary-700 font-bold shadow-sm' 
                      : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'}
                  `}
                >
                  <Icon size={20} />
                  <span>{item.label}</span>
                </Link>
              );
            })}
          </nav>

          <div className="p-4 border-t border-gray-100 text-xs text-gray-400 text-center">
            نسخة تجريبية 1.0.0
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-6xl mx-auto">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { Save, RefreshCw } from 'lucide-react';
import { StorageService } from '../services/storageService';
import { AppSettings, DEFAULT_SETTINGS } from '../types';

const Settings: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [msg, setMsg] = useState('');

  useEffect(() => {
    setSettings(StorageService.getSettings());
  }, []);

  const handleSave = () => {
    StorageService.saveSettings(settings);
    setMsg('تم حفظ الإعدادات بنجاح');
    setTimeout(() => setMsg(''), 3000);
  };

  const handleReset = () => {
    if(window.confirm('هل أنت متأكد من استعادة الإعدادات الافتراضية؟')) {
      setSettings(DEFAULT_SETTINGS);
      StorageService.saveSettings(DEFAULT_SETTINGS);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">إعدادات الخصومات الأساسية</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">اسم الصيدلية</label>
            <input 
              type="text" 
              value={settings.pharmacyName}
              onChange={(e) => setSettings({...settings, pharmacyName: e.target.value})}
              className="w-full p-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
            />
          </div>

          <div className="col-span-full border-t pt-4 mt-2">
            <h3 className="text-lg font-semibold text-gray-700 mb-4">نسب الخصم الافتراضية (%)</h3>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">خصم الصنف العادي (Normal)</label>
            <input 
              type="number" 
              value={settings.discountNormal}
              onChange={(e) => setSettings({...settings, discountNormal: parseFloat(e.target.value) || 0})}
              className="w-full p-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">خصم الصنف الخاص (Special)</label>
            <input 
              type="number" 
              value={settings.discountSpecial}
              onChange={(e) => setSettings({...settings, discountSpecial: parseFloat(e.target.value) || 0})}
              className="w-full p-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">خصومات أخرى</label>
            <input 
              type="number" 
              value={settings.discountOther}
              onChange={(e) => setSettings({...settings, discountOther: parseFloat(e.target.value) || 0})}
              className="w-full p-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
            />
          </div>
        </div>

        <div className="mt-8 flex items-center justify-between">
            <button 
                onClick={handleReset}
                className="flex items-center gap-2 text-red-600 hover:bg-red-50 px-4 py-2 rounded-lg transition-colors"
            >
                <RefreshCw size={18} /> استعادة الافتراضي
            </button>

            <button 
                onClick={handleSave}
                className="flex items-center gap-2 bg-primary-600 text-white px-8 py-3 rounded-xl hover:bg-primary-700 transition-colors shadow-lg shadow-primary-500/30"
            >
                <Save size={20} /> حفظ الإعدادات
            </button>
        </div>

        {msg && (
            <div className="mt-4 p-3 bg-green-50 text-green-700 rounded-lg text-center animate-pulse">
                {msg}
            </div>
        )}
      </div>
    </div>
  );
};

export default Settings;

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Save, ShoppingCart, AlertTriangle, TrendingUp, TrendingDown, Minus } from 'lucide-react';
import { StorageService } from '../services/storageService';
import { CalculatorService } from '../services/calculatorService';
import { AppSettings, DEFAULT_SETTINGS, ItemInput, ItemType, TaxMethod, CalculatedItem, Invoice } from '../types';

const INITIAL_INPUT: ItemInput = {
  id: '',
  name: '',
  type: ItemType.NORMAL,
  qty: 1,
  bonus: 0,
  publicPrice: 0,
  pharmaPrice: 0,
  supplierDiscountVal: 0,
  extraDiscountPct: 0,
  taxValue: 0,
  taxMethod: TaxMethod.PER_UNIT
};

const Calculator: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [currentInput, setCurrentInput] = useState<ItemInput>(INITIAL_INPUT);
  const [invoiceItems, setInvoiceItems] = useState<CalculatedItem[]>([]);
  const [showInvoiceSaved, setShowInvoiceSaved] = useState(false);

  useEffect(() => {
    setSettings(StorageService.getSettings());
  }, []);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setCurrentInput(prev => ({
      ...prev,
      [name]: (name === 'name' || name === 'type' || name === 'taxMethod') 
        ? value 
        : parseFloat(value) || 0
    }));
  };

  const addItem = () => {
    if (!currentInput.name || currentInput.pharmaPrice <= 0) {
      alert('الرجاء إدخال اسم الصنف وسعر الصيدلي');
      return;
    }
    const calculated = CalculatorService.calculateItem({...currentInput, id: Date.now().toString()}, settings);
    setInvoiceItems([...invoiceItems, calculated]);
    setCurrentInput({ ...INITIAL_INPUT, type: currentInput.type }); // Reset but keep last type
  };

  const removeItem = (id: string) => {
    setInvoiceItems(invoiceItems.filter(i => i.id !== id));
  };

  const saveInvoice = () => {
    if (invoiceItems.length === 0) return;

    const totalValue = invoiceItems.reduce((sum, item) => sum + item.netTotalCost, 0);
    const totalItems = invoiceItems.length;
    const totalUnits = invoiceItems.reduce((sum, item) => sum + item.totalUnits, 0);

    const invoice: Invoice = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      items: invoiceItems,
      totalValue,
      totalItems,
      totalUnits
    };

    StorageService.saveInvoice(invoice);
    setShowInvoiceSaved(true);
    setInvoiceItems([]);
    setTimeout(() => setShowInvoiceSaved(false), 3000);
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('ar-EG', { style: 'currency', currency: 'EGP' }).format(val);
  const formatPercent = (val: number) => `${val.toFixed(2)}%`;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
      {/* Input Form */}
      <div className="lg:col-span-4 space-y-4 no-print">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <h2 className="text-xl font-bold mb-4 text-gray-800 flex items-center gap-2">
            <Plus className="text-primary-600" /> إضافة صنف
          </h2>

          <div className="space-y-3">
            <div>
              <label className="text-xs font-semibold text-gray-500">اسم الصنف</label>
              <input 
                name="name" 
                value={currentInput.name} 
                onChange={handleInputChange} 
                className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-primary-500" 
                placeholder="مثال: Panadol Extra"
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-xs font-semibold text-gray-500">النوع (ثابت)</label>
                <select name="type" value={currentInput.type} onChange={handleInputChange} className="w-full p-2 border rounded-lg bg-gray-50">
                  {Object.values(ItemType).map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div>
                <label className="text-xs font-semibold text-gray-500">سعر الجمهور</label>
                <input type="number" name="publicPrice" value={currentInput.publicPrice} onChange={handleInputChange} className="w-full p-2 border rounded-lg" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-xs font-semibold text-gray-500">الكمية</label>
                <input type="number" name="qty" value={currentInput.qty} onChange={handleInputChange} className="w-full p-2 border rounded-lg" />
              </div>
              <div>
                <label className="text-xs font-semibold text-gray-500">بونص</label>
                <input type="number" name="bonus" value={currentInput.bonus} onChange={handleInputChange} className="w-full p-2 border rounded-lg" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
                <div>
                <label className="text-xs font-semibold text-gray-500">سعر الصيدلي (للوحدة)</label>
                <input type="number" name="pharmaPrice" value={currentInput.pharmaPrice} onChange={handleInputChange} className="w-full p-2 border rounded-lg" />
              </div>
               <div>
                <label className="text-xs font-semibold text-gray-500">خصم إضافي %</label>
                <input type="number" name="extraDiscountPct" value={currentInput.extraDiscountPct} onChange={handleInputChange} className="w-full p-2 border rounded-lg" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                 <label className="text-xs font-semibold text-gray-500">خصم مورد (قيمة)</label>
                 <input type="number" name="supplierDiscountVal" value={currentInput.supplierDiscountVal} onChange={handleInputChange} className="w-full p-2 border rounded-lg" />
              </div>
              <div>
                <label className="text-xs font-semibold text-gray-500">الضريبة (قيمة)</label>
                <div className="flex gap-1">
                   <input type="number" name="taxValue" value={currentInput.taxValue} onChange={handleInputChange} className="w-full p-2 border rounded-lg w-2/3" />
                   <select name="taxMethod" value={currentInput.taxMethod} onChange={handleInputChange} className="w-1/3 text-xs border rounded-lg p-1">
                      <option value={TaxMethod.PER_UNIT}>/وحدة</option>
                      <option value={TaxMethod.TOTAL}>كلي</option>
                   </select>
                </div>
              </div>
            </div>

            <button onClick={addItem} className="w-full bg-primary-600 hover:bg-primary-700 text-white font-bold py-3 rounded-xl shadow-lg shadow-primary-500/30 transition-all mt-4">
              حساب وإضافة
            </button>
          </div>
        </div>
      </div>

      {/* Invoice View */}
      <div className="lg:col-span-8 space-y-4">
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
            <h3 className="font-bold text-gray-700 flex items-center gap-2">
              <ShoppingCart size={20} /> مسودة الفاتورة
            </h3>
            <div className="text-sm text-gray-500">
               {invoiceItems.length} أصناف
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-gray-50 text-gray-500 text-xs uppercase">
                <tr>
                  <th className="p-3">الصنف</th>
                  <th className="p-3">العدد</th>
                  <th className="p-3">الصافي</th>
                  <th className="p-3">خصم حقيقي</th>
                  <th className="p-3">رؤى ذكية</th>
                  <th className="p-3 no-print"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {invoiceItems.map((item) => (
                  <tr key={item.id} className="hover:bg-gray-50 transition-colors">
                    <td className="p-3">
                        <div className="font-bold text-gray-800">{item.name}</div>
                        <div className="text-xs text-gray-500">{item.type}</div>
                    </td>
                    <td className="p-3">
                        <div>{item.qty} + {item.bonus}</div>
                        <div className="text-xs text-gray-400">إجمالي: {item.totalUnits}</div>
                    </td>
                    <td className="p-3 font-mono">
                      <div className="font-bold text-primary-700">{formatCurrency(item.netUnitCost)}</div>
                      <div className="text-xs text-gray-400">إجمالي: {formatCurrency(item.netTotalCost)}</div>
                    </td>
                    <td className="p-3">
                      <span className={`font-bold px-2 py-1 rounded text-sm ${item.realDiscountPct > 25 ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'}`}>
                        {formatPercent(item.realDiscountPct)}
                      </span>
                    </td>
                    <td className="p-3">
                        <div className="flex flex-col gap-1">
                            {item.isFakeDiscount && (
                                <span className="flex items-center gap-1 text-xs text-orange-600 bg-orange-50 px-2 py-1 rounded-full w-fit">
                                    <AlertTriangle size={12} /> خصم وهمي
                                </span>
                            )}
                            {item.historyComparison === 'better' && (
                                <span className="flex items-center gap-1 text-xs text-green-600 bg-green-50 px-2 py-1 rounded-full w-fit">
                                    <TrendingDown size={12} /> أفضل {formatPercent(item.priceDifferencePct || 0)}
                                </span>
                            )}
                             {item.historyComparison === 'worse' && (
                                <span className="flex items-center gap-1 text-xs text-red-600 bg-red-50 px-2 py-1 rounded-full w-fit">
                                    <TrendingUp size={12} /> أسوأ {formatPercent(item.priceDifferencePct || 0)}
                                </span>
                            )}
                             {item.historyComparison === 'same' && (
                                <span className="flex items-center gap-1 text-xs text-gray-600 bg-gray-100 px-2 py-1 rounded-full w-fit">
                                    <Minus size={12} /> لا تغيير
                                </span>
                            )}
                        </div>
                    </td>
                    <td className="p-3 no-print">
                      <button onClick={() => removeItem(item.id)} className="text-red-400 hover:text-red-600 transition-colors">
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                ))}
                {invoiceItems.length === 0 && (
                    <tr>
                        <td colSpan={6} className="p-8 text-center text-gray-400">
                            لا توجد أصناف مضافة. استخدم النموذج لإضافة أصناف.
                        </td>
                    </tr>
                )}
              </tbody>
              <tfoot className="bg-gray-50 font-bold text-gray-800">
                 <tr>
                    <td colSpan={2} className="p-4">الإجمالي النهائي</td>
                    <td colSpan={4} className="p-4 text-xl text-primary-700">
                        {formatCurrency(invoiceItems.reduce((acc, i) => acc + i.netTotalCost, 0))}
                    </td>
                 </tr>
              </tfoot>
            </table>
          </div>
        </div>

        {invoiceItems.length > 0 && (
            <div className="flex justify-end gap-4 no-print">
                <button 
                  onClick={() => setInvoiceItems([])}
                  className="px-6 py-3 rounded-xl border border-red-200 text-red-600 hover:bg-red-50"
                >
                    إلغاء الفاتورة
                </button>
                <button 
                    onClick={saveInvoice}
                    className="flex items-center gap-2 bg-green-600 text-white px-8 py-3 rounded-xl hover:bg-green-700 shadow-lg shadow-green-500/30 font-bold"
                >
                    <Save size={20} /> حفظ الفاتورة
                </button>
            </div>
        )}

        {showInvoiceSaved && (
             <div className="fixed bottom-6 left-6 bg-green-600 text-white p-4 rounded-xl shadow-xl flex items-center gap-3 animate-bounce">
                <Save size={24} /> تم حفظ الفاتورة بنجاح في السجل
             </div>
        )}
      </div>
    </div>
  );
};

export default Calculator;

import React, { useState, useEffect } from 'react';
