    e.stopPropagation();
    // In a real app, this would open a specific print window or generate PDF
    // For this prototype, we'll rely on the user navigating to details then printing, 
    // or just trigger window.print() but that prints the whole page. 
    // Let's do a simple hack: Replace body content with invoice then restore (or use a modal).
