import { ItemInput, CalculatedItem, AppSettings, TaxMethod, ItemType } from '../types';
import { StorageService } from './storageService';

export const CalculatorService = {
  calculateItem: (input: ItemInput, settings: AppSettings): CalculatedItem => {
    const {
      type,
      qty,
      bonus,
      publicPrice,
      supplierDiscountVal,
      extraDiscountPct,
      taxValue,
      taxMethod
    } = input;

    // 1. تحديد نسبة خصم النوع من الإعدادات
    let typeDiscountPct = 0;
    switch (type) {
      case ItemType.NORMAL: typeDiscountPct = settings.discountNormal; break;
      case ItemType.SPECIAL: typeDiscountPct = settings.discountSpecial; break;
      case ItemType.OTHER: typeDiscountPct = settings.discountOther; break;
    }

    // 2. الحسابات المالية الصحيحة (بناءً على سعر الجمهور)
    // إجمالي قيمة الجمهور للكمية المشتراة فقط (بدون البونص)
    const totalPublicValue = publicPrice * qty;
    const totalUnits = qty + bonus;

    // وعاء الخصم هو إجمالي سعر الجمهور
    // حساب قيمة خصم النوع
    const typeDiscountValue = totalPublicValue * (typeDiscountPct / 100);

    // حساب قيمة الخصم الإضافي (يُحسب عادة من سعر الجمهور أيضاً في معظم الفواتير)
    const extraDiscountValue = totalPublicValue * (extraDiscountPct / 100);

    // الصافي قبل الضريبة والمورد
    let subTotal = totalPublicValue - typeDiscountValue - extraDiscountValue;

    // طرح خصم المورد النقدي (إن وجد)
    subTotal = subTotal - supplierDiscountVal;

    // 3. حساب الضريبة
    let taxTotal = 0;
    if (taxMethod === TaxMethod.PER_UNIT) {
      taxTotal = taxValue * qty;
    } else {
      taxTotal = taxValue;
    }

    // 4. الإجمالي النهائي للصنف في الفاتورة
    const netTotalCost = subTotal + taxTotal;

    // 5. صافي تكلفة القطعة الواحدة (توزيع الإجمالي على الكمية + البونص)
    const netUnitCost = totalUnits > 0 ? netTotalCost / totalUnits : 0;

    // 6. الخصم الحقيقي النهائي (مقارنة تكلفة القطعة بسعر بيعها للجمهور)
    const realDiscountPct = publicPrice > 0 ? (1 - (netUnitCost / publicPrice)) * 100 : 0;

    const result: CalculatedItem = {
      ...input,
      totalUnits,
      baseTotal: totalPublicValue, // تم التغيير ليعبر عن إجمالي الجمهور
      typeDiscountValue,
      afterTypeDiscount: totalPublicValue - typeDiscountValue,
      extraDiscountValue,
      taxTotal,
      netTotalCost,
      netUnitCost,
      realDiscountPct,
      historyComparison: 'new',
      isFakeDiscount: false
    };

    // مقارنة التاريخ (كما هي)
    const lastPurchase = StorageService.getLastPurchaseItem(input.name);
    if (lastPurchase) {
      const diff = netUnitCost - lastPurchase.netUnitCost;
      const pctDiff = lastPurchase.netUnitCost > 0 ? (diff / lastPurchase.netUnitCost) * 100 : 0;
      result.priceDifferencePct = Math.abs(pctDiff);

      if (diff < -0.001) result.historyComparison = 'better';
      else if (diff > 0.001) result.historyComparison = 'worse';
      else result.historyComparison = 'same';
    }

    // كشف الخصم الوهمي
    // إذا كان الخصم الحقيقي أقل من خصم النوع المعلن بأكثر من 1% (بسبب نقص البونص أو زيادة التكلفة)
    if (realDiscountPct < (typeDiscountPct - 1)) {
      result.isFakeDiscount = true;
    }

    return result;
  }
};

