                    </datalist>
                </div>
                <div className="w-24">
                     <label className="text-xs font-semibold text-gray-500 block mb-1">النوع</label>
                     <select name="type" value={currentInput.type} onChange={handleInputChange} className="w-full p-2 border rounded-lg bg-gray-50 text-sm">
