const Calculator: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [currentInput, setCurrentInput] = useState<ItemInput>(INITIAL_INPUT);
  const [invoiceItems, setInvoiceItems] = useState<CalculatedItem[]>([]);
  const [showInvoiceSaved, setShowInvoiceSaved] = useState(false);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [knownItemNames, setKnownItemNames] = useState<string[]>([]);
  const [selectedSupplierId, setSelectedSupplierId] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [lastHistoryItem, setLastHistoryItem] = useState<CalculatedItem | null>(null);
  const [bonusSuggestion, setBonusSuggestion] = useState<CalculatedItem | null>(null);
  const [editingInvoiceId, setEditingInvoiceId] = useState<string | null>(null);

  useEffect(() => {
    setSettings(StorageService.getSettings());
    setSuppliers(StorageService.getSuppliers());
    setKnownItemNames(StorageService.getAllItemNames());

    // Check for Edit Mode
    if (location.state && location.state.editInvoice) {
        const inv = location.state.editInvoice as Invoice;
        setEditingInvoiceId(inv.id);
        setInvoiceItems(inv.items);
        setInvoiceNumber(inv.invoiceNumber || '');
        setSelectedSupplierId(inv.supplierId || '');
        // Clear state to avoid reload issues
        window.history.replaceState({}, document.title);
    }
  }, [location.state]);

  useEffect(() => {
    if (currentInput.name.length > 2) {
        // 1. Try to find in Catalog first for price autofill
        const catalogItem = StorageService.getCatalogItemByName(currentInput.name);
        if (catalogItem && currentInput.publicPrice === 0 && currentInput.pharmaPrice === 0) {
            setCurrentInput(prev => ({ 
                ...prev, 
                type: catalogItem.type, 
                publicPrice: catalogItem.publicPrice,
                pharmaPrice: catalogItem.pharmaPrice 
            }));
        }

        // 2. History & Bonus logic
        const history = StorageService.getLastPurchaseItem(currentInput.name);
        setLastHistoryItem(history);
        if (currentInput.bonus === 0 && currentInput.qty > 0) {
            const bonusItem = StorageService.getItemWithBonusHistory(currentInput.name);
            if (bonusItem && bonusItem.qty > currentInput.qty) {
                setBonusSuggestion(bonusItem);
            } else {
                setBonusSuggestion(null);
            }
        } else {
            setBonusSuggestion(null);
        }
    } else {
        setLastHistoryItem(null);
        setBonusSuggestion(null);
    }
  }, [currentInput.name, currentInput.qty, currentInput.bonus]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setCurrentInput(prev => ({
      ...prev,
      [name]: (name === 'name' || name === 'type' || name === 'taxMethod') 
        ? value 
        : parseFloat(value) || 0
    }));
  };

  const handleTaxCheck = () => {
    setCurrentInput(prev => ({
        ...prev,
        taxMethod: prev.taxMethod === TaxMethod.PER_UNIT ? TaxMethod.TOTAL : TaxMethod.PER_UNIT
    }));
  };

  const getEffectiveDiscount = (): number => {
    if (selectedSupplierId) {
        const supplier = suppliers.find(s => s.id === selectedSupplierId);
        if (supplier) {
            if (currentInput.type === ItemType.NORMAL && supplier.discountNormal !== undefined) return supplier.discountNormal;
            if (currentInput.type === ItemType.SPECIAL && supplier.discountSpecial !== undefined) return supplier.discountSpecial;
            if (currentInput.type === ItemType.OTHER && supplier.discountOther !== undefined) return supplier.discountOther;
        }
    }
    return -1;
  };

  const addItem = () => {
    if (!currentInput.name || (currentInput.pharmaPrice <= 0 && currentInput.publicPrice <= 0)) {
      alert('الرجاء إدخال اسم الصنف والسعر');
      return;
    }

    const effectiveDiscount = getEffectiveDiscount();
    const itemToCalc = {
        ...currentInput, 
        id: Date.now().toString() + Math.random(),
        customTypeDiscount: effectiveDiscount >= 0 ? effectiveDiscount : undefined
    };

    const calculated = CalculatorService.calculateItem(itemToCalc, settings);
    setInvoiceItems([...invoiceItems, calculated]);
    setCurrentInput({ ...INITIAL_INPUT, type: currentInput.type }); 
    setLastHistoryItem(null);
    setBonusSuggestion(null);
  };

  const removeItem = (id: string) => {
    setInvoiceItems(invoiceItems.filter(i => i.id !== id));
  };

  const saveInvoice = () => {
    if (invoiceItems.length === 0) return;
    if (!selectedSupplierId) {
        alert('تنبيه: لا يمكن حفظ الفاتورة بدون اختيار مورد.');
        return;
    }
    const supplierObj = suppliers.find(s => s.id === selectedSupplierId);
    const totalValue = invoiceItems.reduce((sum, item) => sum + item.netTotalCost, 0);

    // Preserve Original Date if Editing, else new Date
    const originalInvoice = editingInvoiceId ? StorageService.getInvoiceById(editingInvoiceId) : null;

    const invoice: Invoice = {
      id: editingInvoiceId || Date.now().toString(),
      date: originalInvoice ? originalInvoice.date : new Date().toISOString(),
      invoiceNumber,
      supplierId: selectedSupplierId,
      supplierName: supplierObj ? supplierObj.name : 'غير محدد',
      items: invoiceItems,
      totalValue,
      totalItems: invoiceItems.length,
      totalUnits: invoiceItems.reduce((sum, item) => sum + item.totalUnits, 0),
      isSold: originalInvoice ? originalInvoice.isSold : false
    };

    StorageService.saveInvoice(invoice);
    setKnownItemNames(StorageService.getAllItemNames());
    setShowInvoiceSaved(true);

    // Reset or Navigate back
    if (editingInvoiceId) {
        setTimeout(() => navigate('/invoices'), 1500);
    } else {
        setInvoiceItems([]);
        setSelectedSupplierId('');
        setInvoiceNumber('');
        setTimeout(() => setShowInvoiceSaved(false), 3000);
    }
  };

  const groupedItems = useMemo(() => {
    const groups: Partial<Record<ItemType, CalculatedItem[]>> = {
        [ItemType.NORMAL]: [],
        [ItemType.SPECIAL]: [],
        [ItemType.OTHER]: []
    };
    invoiceItems.forEach(item => {
        if (groups[item.type]) groups[item.type]?.push(item);
        else groups[ItemType.OTHER]?.push(item);
    });
    return groups;
  }, [invoiceItems]);

  const currentSupplierName = suppliers.find(s => s.id === selectedSupplierId)?.name || '';

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
      <div className="lg:col-span-4 space-y-4 no-print">

        {editingInvoiceId && (
            <div className="bg-blue-50 border border-blue-200 p-4 rounded-xl flex items-center justify-between">
                <span className="text-blue-700 font-bold flex items-center gap-2"><ArrowLeft size={18} /> وضع تعديل الفاتورة</span>
                <button onClick={() => navigate('/invoices')} className="text-xs underline text-blue-500">عودة</button>
            </div>
        )}

        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 space-y-3">
             <div className="flex items-center gap-2 mb-2 text-primary-700 font-bold border-b pb-2">
                <User size={18} />
                <span>بيانات الفاتورة والمورد</span>
             </div>
             <div>
                <label className="text-xs font-semibold text-gray-500 mb-1 block">اسم المورد *</label>
                <select value={selectedSupplierId} onChange={(e) => setSelectedSupplierId(e.target.value)} className={`w-full p-2 border rounded-lg bg-gray-50 ${!selectedSupplierId ? 'border-orange-300 bg-orange-50' : 'border-green-300 bg-green-50'}`}>
                    <option value="">-- اختر مورد لتطبيق خصوماته --</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
             </div>
             <div>
                <label className="text-xs font-semibold text-gray-500 mb-1 block">رقم الفاتورة الورقية</label>
                <input type="text" value={invoiceNumber} onChange={(e) => setInvoiceNumber(e.target.value)} placeholder="مثال: 10255" className="w-full p-2 border rounded-lg bg-gray-50" />
             </div>
        </div>

        <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                <Plus className="text-primary-600" /> إضافة صنف
            </h2>
            <button 
                onClick={saveInvoice} 
                disabled={invoiceItems.length === 0}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-1 transition-colors ${invoiceItems.length > 0 ? 'bg-green-600 text-white hover:bg-green-700 shadow-sm' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
            >
                <Save size={14} /> حفظ سريع
            </button>
          </div>
          <div className="space-y-4">
            <div className="flex gap-2">
                <div className="flex-1 relative">
                    <label className="text-xs font-semibold text-gray-500 block mb-1">اسم الصنف</label>
                    <input list="item-names" name="name" value={currentInput.name} onChange={handleInputChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-primary-500" placeholder="ابحث..." autoComplete="off" />
                    <datalist id="item-names">
                        {knownItemNames.map((n, i) => <option key={i} value={n} />)}
                    </datalist>
                </div>
                <div className="w-24">
                     <label className="text-xs font-semibold text-gray-500 block mb-1">النوع</label>
                     <select name="type" value={currentInput.type} onChange={handleInputChange} className="w-full p-2 border rounded-lg bg-gray-50 text-sm">
                        {Object.entries(ItemTypeShort).map(([key, abbr]) => <option key={key} value={key}>{abbr}</option>)}
                     </select>
                </div>
            </div>

            {/* Display active discount context */}
            {selectedSupplierId && (
                <div className="text-xs text-green-600 bg-green-50 p-2 rounded flex justify-between items-center">
                    <span>خصم المورد النشط:</span>
                    <span className="font-bold">
                        {getEffectiveDiscount() >= 0 ? `${getEffectiveDiscount()}%` : 'افتراضي'}
                    </span>
                </div>
            )}

            <div className="space-y-2">
                {lastHistoryItem && (
                    <div className="bg-blue-50 border border-blue-100 rounded-lg p-3 flex items-start gap-2 text-sm text-blue-800 animate-fade-in">
                        <Info size={16} className="mt-0.5 shrink-0" />
                        <div><div className="font-bold">سجل سابق:</div><div>سعر الصافي: {formatCurrency(lastHistoryItem.netUnitCost)}</div><div>الخصم: {formatPercent(lastHistoryItem.realDiscountPct)}</div></div>
                    </div>
                )}
                {bonusSuggestion && (
                     <div className="bg-purple-50 border border-purple-100 rounded-lg p-3 flex items-start gap-2 text-sm text-purple-800 animate-fade-in cursor-pointer hover:bg-purple-100" onClick={() => setCurrentInput(prev => ({...prev, qty: bonusSuggestion.qty, bonus: bonusSuggestion.bonus}))}>
                        <Lightbulb size={16} className="mt-0.5 shrink-0 text-purple-600" />
                        <div><div className="font-bold mb-1">💡 نصيحة ذكية (اضغط للتطبيق)</div><div>سابقاً اشتريت {bonusSuggestion.qty} + {bonusSuggestion.bonus} بونص.</div></div>
                    </div>
                )}
            </div>
            <div className="flex gap-2">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">العدد</label><input type="number" name="qty" value={currentInput.qty} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">بونص</label><input type="number" name="bonus" value={currentInput.bonus} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex gap-2">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">سعر الجمهور</label><input type="number" name="publicPrice" value={currentInput.publicPrice} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">سعر الصيدلي</label><input type="number" name="pharmaPrice" value={currentInput.pharmaPrice} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex gap-2 items-end">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">خ. مورد (قيمة)</label><input type="number" name="supplierDiscountVal" value={currentInput.supplierDiscountVal} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">خ. إضافي %</label><input type="number" name="extraDiscountPct" value={currentInput.extraDiscountPct} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1 relative"><label className="text-xs font-semibold text-gray-500 block mb-1">الضريبة</label><input type="number" name="taxValue" value={currentInput.taxValue} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer select-none" onClick={handleTaxCheck}>
                {currentInput.taxMethod === TaxMethod.TOTAL ? <CheckSquare size={18} className="text-primary-600" /> : <Square size={18} className="text-gray-400" />}
                <span>الضريبة مبلغ كلي</span>
            </div>
            <button onClick={addItem} className="w-full bg-primary-600 hover:bg-primary-700 text-white font-bold py-3 rounded-xl shadow-lg mt-2">حساب وإضافة</button>
          </div>
        </div>
      </div>
      <div className="lg:col-span-8 space-y-4">

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
            <h3 className="font-bold text-gray-700 flex items-center gap-2"><ShoppingCart size={20} /> مسودة الفاتورة {currentSupplierName && ` - ${currentSupplierName}`}</h3>
            <div className="text-sm text-gray-500">{invoiceItems.length} أصناف</div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-gray-50 text-gray-500 text-xs uppercase"><tr><th className="p-3">الصنف</th><th className="p-3">العدد</th><th className="p-3">الصافي</th><th className="p-3 text-center">خصم حقيقي</th><th className="p-3 text-center">تحليل</th><th className="p-3 no-print"></th></tr></thead>
              <tbody className="divide-y divide-gray-100">
                {Object.entries(groupedItems).map(([type, items]) => {
                    const typedItems = items as CalculatedItem[];
                    if (!typedItems || typedItems.length === 0) return null;
                    return (
                        <React.Fragment key={type}>
                            <tr className="bg-primary-50 border-y border-primary-100"><td colSpan={6} className="p-2 px-4 font-bold text-primary-700">{type}</td></tr>
                            {typedItems.map(item => <ItemRow key={item.id} item={item} onRemove={removeItem} />)}
                        </React.Fragment>
                    );
                })}
                {invoiceItems.length === 0 && <tr><td colSpan={6} className="p-8 text-center text-gray-400">لا توجد أصناف مضافة.</td></tr>}
              </tbody>
              <tfoot className="bg-gray-800 text-white font-bold"><tr><td colSpan={2} className="p-4 text-lg">الإجمالي النهائي</td><td colSpan={4} className="p-4 text-2xl text-left">{formatCurrency(invoiceItems.reduce((acc, i) => acc + i.netTotalCost, 0))}</td></tr></tfoot>
            </table>
          </div>
        </div>
        {invoiceItems.length > 0 && (
            <div className="flex justify-end gap-4 no-print">
                <button onClick={() => { setInvoiceItems([]); setEditingInvoiceId(null); navigate('/invoices'); }} className="px-6 py-3 rounded-xl border border-red-200 text-red-600">إلغاء</button>
                <button onClick={saveInvoice} className="bg-green-600 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2"><Save size={20} /> {editingInvoiceId ? 'حفظ التعديلات' : 'حفظ الفاتورة'}</button>
            </div>
        )}
        {showInvoiceSaved && <div className="fixed bottom-6 left-6 bg-green-600 text-white p-4 rounded-xl shadow-xl flex items-center gap-3 animate-bounce z-50"><Save size={24} /> {editingInvoiceId ? 'تم تحديث الفاتورة' : 'تم حفظ الفاتورة'}</div>}
      </div>
    </div>
  );
};

export default Calculator;

import React, { useState, useEffect, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Plus, Trash2, Save, ShoppingCart, AlertTriangle, TrendingUp, TrendingDown, Minus, Calculator as CalculatorIcon, Store, FileDigit, Info, CheckSquare, Square, Lightbulb, User, ArrowLeft } from 'lucide-react';
import { StorageService } from '../services/storageService';
import { CalculatorService } from '../services/calculatorService';
import { AppSettings, DEFAULT_SETTINGS, ItemInput, ItemType, ItemTypeShort, TaxMethod, CalculatedItem, Invoice, Supplier } from '../types';

const INITIAL_INPUT: ItemInput = {
  id: '',
  name: '',
  type: ItemType.NORMAL,
  qty: 1,
  bonus: 0,
  publicPrice: 0,
  pharmaPrice: 0,
  supplierDiscountVal: 0,
  extraDiscountPct: 0,
  taxValue: 0,
  taxMethod: TaxMethod.PER_UNIT
};

const formatCurrency = (val: number) => new Intl.NumberFormat('ar-EG', { style: 'currency', currency: 'EGP' }).format(val);
const formatPercent = (val: number) => `${val.toFixed(2)}%`;

interface ItemRowProps {
  item: CalculatedItem;
  onRemove: (id: string) => void;
}

const ItemRow: React.FC<ItemRowProps> = ({ item, onRemove }) => (
    <tr className="hover:bg-gray-50 transition-colors border-b border-gray-100 last:border-0">
        <td className="p-3">
            <div className="font-bold text-gray-800">{item.name}</div>
        </td>
        <td className="p-3">
            <div>{item.qty} + {item.bonus}</div>
            <div className="text-xs text-gray-400">إجمالي: {item.totalUnits}</div>
        </td>
        <td className="p-3 font-mono text-sm">
            <div className="font-bold text-primary-700">{formatCurrency(item.netUnitCost)}</div>
            <div className="text-xs text-gray-400">الإجمالي: {formatCurrency(item.netTotalCost)}</div>
        </td>
        <td className="p-3 text-center">
            <span className={`inline-block font-bold px-2 py-1 rounded text-xs ${item.realDiscountPct > 25 ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'}`}>
            {formatPercent(item.realDiscountPct)}
            </span>
        </td>
        <td className="p-3">
            <div className="flex justify-center gap-2">
                {item.isFakeDiscount && (
                    <div className="group relative">
                        <div className="bg-orange-100 text-orange-600 p-1.5 rounded-full cursor-help">
                            <AlertTriangle size={16} />
                        </div>
                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover:block bg-gray-800 text-white text-xs p-2 rounded whitespace-nowrap z-10 shadow-lg">
                            خصم وهمي: الخصم الحقيقي أقل بكثير من المتوقع
                        </div>
                    </div>
                )}
                {item.historyComparison !== 'new' && item.historyComparison && (
                    <div className="group relative">
                        <div className={`p-1.5 rounded-full cursor-help ${
                            item.historyComparison === 'better' ? 'bg-green-100 text-green-600' :
                            item.historyComparison === 'worse' ? 'bg-red-100 text-red-600' :
                            'bg-gray-100 text-gray-600'
                        }`}>
                            {item.historyComparison === 'better' && <TrendingDown size={16} />}
                            {item.historyComparison === 'worse' && <TrendingUp size={16} />}
                            {item.historyComparison === 'same' && <Minus size={16} />}
                        </div>
                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover:block bg-gray-800 text-white text-xs p-2 rounded whitespace-nowrap z-10 shadow-lg">
                            {item.historyComparison === 'better' && `سعر أفضل بـ ${formatPercent(item.priceDifferencePct || 0)} عن آخر مرة`}
                            {item.historyComparison === 'worse' && `سعر أغلى بـ ${formatPercent(item.priceDifferencePct || 0)} عن آخر مرة`}
                            {item.historyComparison === 'same' && 'نفس سعر الشراء السابق'}
                        </div>
                    </div>
                )}
            </div>
        </td>
        <td className="p-3 no-print text-center">
            <button onClick={() => onRemove(item.id)} className="text-red-400 hover:text-red-600 transition-colors p-1 hover:bg-red-50 rounded">
            <Trash2 size={16} />
            </button>
        </td>
    </tr>
);

const Calculator: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [currentInput, setCurrentInput] = useState<ItemInput>(INITIAL_INPUT);
  const [invoiceItems, setInvoiceItems] = useState<CalculatedItem[]>([]);
  const [showInvoiceSaved, setShowInvoiceSaved] = useState(false);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [knownItemNames, setKnownItemNames] = useState<string[]>([]);
  const [selectedSupplierId, setSelectedSupplierId] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [lastHistoryItem, setLastHistoryItem] = useState<CalculatedItem | null>(null);
  const [bonusSuggestion, setBonusSuggestion] = useState<CalculatedItem | null>(null);
  const [editingInvoiceId, setEditingInvoiceId] = useState<string | null>(null);

  useEffect(() => {
    setSettings(StorageService.getSettings());
    setSuppliers(StorageService.getSuppliers());
    setKnownItemNames(StorageService.getAllItemNames());

    // Check for Edit Mode
    if (location.state && location.state.editInvoice) {
        const inv = location.state.editInvoice as Invoice;
        setEditingInvoiceId(inv.id);
        setInvoiceItems(inv.items);
        setInvoiceNumber(inv.invoiceNumber || '');
        setSelectedSupplierId(inv.supplierId || '');
        // Clear state to avoid reload issues
        window.history.replaceState({}, document.title);
    }
  }, [location.state]);

  useEffect(() => {
    if (currentInput.name.length > 1) {
        // 1. Try to find in Catalog first for price autofill
        const catalogItem = StorageService.getCatalogItemByName(currentInput.name);

        // إذا وجدنا الصنف في الدليل، نقوم بتحديث البيانات فوراً حتى لو كانت الحقول ممتلئة سابقاً
        // يتم التحقق من اختلاف القيم لتجنب إعادة الرسم غير الضرورية
        if (catalogItem) {
            if (currentInput.type !== catalogItem.type || 
                currentInput.publicPrice !== catalogItem.publicPrice || 
                currentInput.pharmaPrice !== catalogItem.pharmaPrice) {

                setCurrentInput(prev => ({ 
                    ...prev, 
                    type: catalogItem.type, 
                    publicPrice: catalogItem.publicPrice,
                    pharmaPrice: catalogItem.pharmaPrice 
                }));
            }
        }

        // 2. History & Bonus logic
        const history = StorageService.getLastPurchaseItem(currentInput.name);
        setLastHistoryItem(history);
        if (currentInput.bonus === 0 && currentInput.qty > 0) {
            const bonusItem = StorageService.getItemWithBonusHistory(currentInput.name);
            if (bonusItem && bonusItem.qty > currentInput.qty) {
                setBonusSuggestion(bonusItem);
            } else {
                setBonusSuggestion(null);
            }
        } else {
            setBonusSuggestion(null);
        }
    } else {
        setLastHistoryItem(null);
        setBonusSuggestion(null);
    }
  }, [currentInput.name, currentInput.qty, currentInput.bonus]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setCurrentInput(prev => ({
      ...prev,
      [name]: (name === 'name' || name === 'type' || name === 'taxMethod') 
        ? value 
        : parseFloat(value) || 0
    }));
  };

  const handleTaxCheck = () => {
    setCurrentInput(prev => ({
        ...prev,
        taxMethod: prev.taxMethod === TaxMethod.PER_UNIT ? TaxMethod.TOTAL : TaxMethod.PER_UNIT
    }));
  };

  const getEffectiveDiscount = (): number => {
    if (selectedSupplierId) {
        const supplier = suppliers.find(s => s.id === selectedSupplierId);
        if (supplier) {
            if (currentInput.type === ItemType.NORMAL && supplier.discountNormal !== undefined) return supplier.discountNormal;
            if (currentInput.type === ItemType.SPECIAL && supplier.discountSpecial !== undefined) return supplier.discountSpecial;
            if (currentInput.type === ItemType.OTHER && supplier.discountOther !== undefined) return supplier.discountOther;
        }
    }
    return -1;
  };

  const addItem = () => {
    if (!currentInput.name || (currentInput.pharmaPrice <= 0 && currentInput.publicPrice <= 0)) {
      alert('الرجاء إدخال اسم الصنف والسعر');
      return;
    }

    const effectiveDiscount = getEffectiveDiscount();
    const itemToCalc = {
        ...currentInput, 
        id: Date.now().toString() + Math.random(),
        customTypeDiscount: effectiveDiscount >= 0 ? effectiveDiscount : undefined
    };

    const calculated = CalculatorService.calculateItem(itemToCalc, settings);
    setInvoiceItems([...invoiceItems, calculated]);
    setCurrentInput({ ...INITIAL_INPUT, type: currentInput.type }); 
    setLastHistoryItem(null);
    setBonusSuggestion(null);
  };

  const removeItem = (id: string) => {
    setInvoiceItems(invoiceItems.filter(i => i.id !== id));
  };

  const saveInvoice = () => {
    if (invoiceItems.length === 0) return;
    if (!selectedSupplierId) {
        alert('تنبيه: لا يمكن حفظ الفاتورة بدون اختيار مورد.');
        return;
    }
    const supplierObj = suppliers.find(s => s.id === selectedSupplierId);
    const totalValue = invoiceItems.reduce((sum, item) => sum + item.netTotalCost, 0);

    // Preserve Original Date if Editing, else new Date
    const originalInvoice = editingInvoiceId ? StorageService.getInvoiceById(editingInvoiceId) : null;

    const invoice: Invoice = {
      id: editingInvoiceId || Date.now().toString(),
      date: originalInvoice ? originalInvoice.date : new Date().toISOString(),
      invoiceNumber,
      supplierId: selectedSupplierId,
      supplierName: supplierObj ? supplierObj.name : 'غير محدد',
      items: invoiceItems,
      totalValue,
      totalItems: invoiceItems.length,
      totalUnits: invoiceItems.reduce((sum, item) => sum + item.totalUnits, 0),
      isSold: originalInvoice ? originalInvoice.isSold : false
    };

    StorageService.saveInvoice(invoice);
    setKnownItemNames(StorageService.getAllItemNames());
    setShowInvoiceSaved(true);

    // Reset or Navigate back
    if (editingInvoiceId) {
        setTimeout(() => navigate('/invoices'), 1500);
    } else {
        setInvoiceItems([]);
        setSelectedSupplierId('');
        setInvoiceNumber('');
        setTimeout(() => setShowInvoiceSaved(false), 3000);
    }
  };

  const groupedItems = useMemo(() => {
    const groups: Partial<Record<ItemType, CalculatedItem[]>> = {
        [ItemType.NORMAL]: [],
        [ItemType.SPECIAL]: [],
        [ItemType.OTHER]: []
    };
    invoiceItems.forEach(item => {
        if (groups[item.type]) groups[item.type]?.push(item);
        else groups[ItemType.OTHER]?.push(item);
    });
    return groups;
  }, [invoiceItems]);

  const currentSupplierName = suppliers.find(s => s.id === selectedSupplierId)?.name || '';

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
      <div className="lg:col-span-4 space-y-4 no-print">

        {editingInvoiceId && (
            <div className="bg-blue-50 border border-blue-200 p-4 rounded-xl flex items-center justify-between">
                <span className="text-blue-700 font-bold flex items-center gap-2"><ArrowLeft size={18} /> وضع تعديل الفاتورة</span>
                <button onClick={() => navigate('/invoices')} className="text-xs underline text-blue-500">عودة</button>
            </div>
        )}

        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 space-y-3">
             <div className="flex items-center gap-2 mb-2 text-primary-700 font-bold border-b pb-2">
                <User size={18} />
                <span>بيانات الفاتورة والمورد</span>
             </div>
             <div>
                <label className="text-xs font-semibold text-gray-500 mb-1 block">اسم المورد *</label>
                <select value={selectedSupplierId} onChange={(e) => setSelectedSupplierId(e.target.value)} className={`w-full p-2 border rounded-lg bg-gray-50 ${!selectedSupplierId ? 'border-orange-300 bg-orange-50' : 'border-green-300 bg-green-50'}`}>
                    <option value="">-- اختر مورد لتطبيق خصوماته --</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
             </div>
             <div>
                <label className="text-xs font-semibold text-gray-500 mb-1 block">رقم الفاتورة الورقية</label>
                <input type="text" value={invoiceNumber} onChange={(e) => setInvoiceNumber(e.target.value)} placeholder="مثال: 10255" className="w-full p-2 border rounded-lg bg-gray-50" />
             </div>
        </div>

        <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                <Plus className="text-primary-600" /> إضافة صنف
            </h2>
            <button 
                onClick={saveInvoice} 
                disabled={invoiceItems.length === 0}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-1 transition-colors ${invoiceItems.length > 0 ? 'bg-green-600 text-white hover:bg-green-700 shadow-sm' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
            >
                <Save size={14} /> حفظ سريع
            </button>
          </div>
          <div className="space-y-4">
            <div className="flex gap-2">
                <div className="flex-1 relative">
                    <label className="text-xs font-semibold text-gray-500 block mb-1">اسم الصنف</label>
                    <input list="item-names" name="name" value={currentInput.name} onChange={handleInputChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-primary-500" placeholder="ابحث..." autoComplete="off" />
                    <datalist id="item-names">
                        {knownItemNames.map((n, i) => <option key={i} value={n} />)}
                    </datalist>
                </div>
                <div className="w-24">
                     <label className="text-xs font-semibold text-gray-500 block mb-1">النوع</label>
                     <select name="type" value={currentInput.type} onChange={handleInputChange} className="w-full p-2 border rounded-lg bg-gray-50 text-sm">
                        {Object.entries(ItemTypeShort).map(([key, abbr]) => <option key={key} value={key}>{abbr}</option>)}
                     </select>
                </div>
            </div>

            {/* Display active discount context */}
            {selectedSupplierId && (
                <div className="text-xs text-green-600 bg-green-50 p-2 rounded flex justify-between items-center">
                    <span>خصم المورد النشط:</span>
                    <span className="font-bold">
                        {getEffectiveDiscount() >= 0 ? `${getEffectiveDiscount()}%` : 'افتراضي'}
                    </span>
                </div>
            )}

            <div className="space-y-2">
                {lastHistoryItem && (
                    <div className="bg-blue-50 border border-blue-100 rounded-lg p-3 flex items-start gap-2 text-sm text-blue-800 animate-fade-in">
                        <Info size={16} className="mt-0.5 shrink-0" />
                        <div><div className="font-bold">سجل سابق:</div><div>سعر الصافي: {formatCurrency(lastHistoryItem.netUnitCost)}</div><div>الخصم: {formatPercent(lastHistoryItem.realDiscountPct)}</div></div>
                    </div>
                )}
                {bonusSuggestion && (
                     <div className="bg-purple-50 border border-purple-100 rounded-lg p-3 flex items-start gap-2 text-sm text-purple-800 animate-fade-in cursor-pointer hover:bg-purple-100" onClick={() => setCurrentInput(prev => ({...prev, qty: bonusSuggestion.qty, bonus: bonusSuggestion.bonus}))}>
                        <Lightbulb size={16} className="mt-0.5 shrink-0 text-purple-600" />
                        <div><div className="font-bold mb-1">💡 نصيحة ذكية (اضغط للتطبيق)</div><div>سابقاً اشتريت {bonusSuggestion.qty} + {bonusSuggestion.bonus} بونص.</div></div>
                    </div>
                )}
            </div>
            <div className="flex gap-2">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">العدد</label><input type="number" name="qty" value={currentInput.qty} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">بونص</label><input type="number" name="bonus" value={currentInput.bonus} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex gap-2">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">سعر الجمهور</label><input type="number" name="publicPrice" value={currentInput.publicPrice} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">سعر الصيدلي</label><input type="number" name="pharmaPrice" value={currentInput.pharmaPrice} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex gap-2 items-end">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">خ. مورد (قيمة)</label><input type="number" name="supplierDiscountVal" value={currentInput.supplierDiscountVal} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">خ. إضافي %</label><input type="number" name="extraDiscountPct" value={currentInput.extraDiscountPct} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1 relative"><label className="text-xs font-semibold text-gray-500 block mb-1">الضريبة</label><input type="number" name="taxValue" value={currentInput.taxValue} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer select-none" onClick={handleTaxCheck}>
                {currentInput.taxMethod === TaxMethod.TOTAL ? <CheckSquare size={18} className="text-primary-600" /> : <Square size={18} className="text-gray-400" />}
                <span>الضريبة مبلغ كلي</span>
            </div>
            <button onClick={addItem} className="w-full bg-primary-600 hover:bg-primary-700 text-white font-bold py-3 rounded-xl shadow-lg mt-2">حساب وإضافة</button>
          </div>
        </div>
      </div>
      <div className="lg:col-span-8 space-y-4">

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
            <h3 className="font-bold text-gray-700 flex items-center gap-2"><ShoppingCart size={20} /> مسودة الفاتورة {currentSupplierName && ` - ${currentSupplierName}`}</h3>
            <div className="text-sm text-gray-500">{invoiceItems.length} أصناف</div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-gray-50 text-gray-500 text-xs uppercase"><tr><th className="p-3">الصنف</th><th className="p-3">العدد</th><th className="p-3">الصافي</th><th className="p-3 text-center">خصم حقيقي</th><th className="p-3 text-center">تحليل</th><th className="p-3 no-print"></th></tr></thead>
              <tbody className="divide-y divide-gray-100">
                {Object.entries(groupedItems).map(([type, items]) => {
                    const typedItems = items as CalculatedItem[];
                    if (!typedItems || typedItems.length === 0) return null;
                    return (
                        <React.Fragment key={type}>
                            <tr className="bg-primary-50 border-y border-primary-100"><td colSpan={6} className="p-2 px-4 font-bold text-primary-700">{type}</td></tr>
                            {typedItems.map(item => <ItemRow key={item.id} item={item} onRemove={removeItem} />)}
                        </React.Fragment>
                    );
                })}
                {invoiceItems.length === 0 && <tr><td colSpan={6} className="p-8 text-center text-gray-400">لا توجد أصناف مضافة.</td></tr>}
              </tbody>
              <tfoot className="bg-gray-800 text-white font-bold"><tr><td colSpan={2} className="p-4 text-lg">الإجمالي النهائي</td><td colSpan={4} className="p-4 text-2xl text-left">{formatCurrency(invoiceItems.reduce((acc, i) => acc + i.netTotalCost, 0))}</td></tr></tfoot>
            </table>
          </div>
        </div>
        {invoiceItems.length > 0 && (
            <div className="flex justify-end gap-4 no-print">
                <button onClick={() => { setInvoiceItems([]); setEditingInvoiceId(null); navigate('/invoices'); }} className="px-6 py-3 rounded-xl border border-red-200 text-red-600">إلغاء</button>
                <button onClick={saveInvoice} className="bg-green-600 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2"><Save size={20} /> {editingInvoiceId ? 'حفظ التعديلات' : 'حفظ الفاتورة'}</button>
            </div>
        )}
        {showInvoiceSaved && <div className="fixed bottom-6 left-6 bg-green-600 text-white p-4 rounded-xl shadow-xl flex items-center gap-3 animate-bounce z-50"><Save size={24} /> {editingInvoiceId ? 'تم تحديث الفاتورة' : 'تم حفظ الفاتورة'}</div>}
      </div>
    </div>
  );
};

export default Calculator;

import React, { useState, useEffect, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { Plus, Trash2, Save, ShoppingCart, AlertTriangle, TrendingUp, TrendingDown, Minus, Calculator as CalculatorIcon, Store, FileDigit, Info, CheckSquare, Square, Lightbulb, User, ArrowLeft } from 'lucide-react';
import { StorageService } from '../services/storageService';
import { CalculatorService } from '../services/calculatorService';
import { AppSettings, DEFAULT_SETTINGS, ItemInput, ItemType, ItemTypeShort, TaxMethod, CalculatedItem, Invoice, Supplier } from '../types';

const INITIAL_INPUT: ItemInput = {
  id: '',
  name: '',
  type: ItemType.NORMAL,
  qty: 1,
  bonus: 0,
  publicPrice: 0,
  pharmaPrice: 0,
  supplierDiscountVal: 0,
  extraDiscountPct: 0,
  taxValue: 0,
  taxMethod: TaxMethod.PER_UNIT
};

// تحديث: إظهار 3 أرقام عشرية للنسبة المئوية
const formatCurrency = (val: number) => new Intl.NumberFormat('ar-EG', { style: 'currency', currency: 'EGP' }).format(val);
const formatPercent = (val: number) => `${val.toFixed(3)}%`;

interface ItemRowProps {
  item: CalculatedItem;
  onRemove: (id: string) => void;
}

const ItemRow: React.FC<ItemRowProps> = ({ item, onRemove }) => (
    <tr className="hover:bg-gray-50 transition-colors border-b border-gray-100 last:border-0">
        <td className="p-3">
            <div className="font-bold text-gray-800">{item.name}</div>
        </td>
        <td className="p-3">
            <div>{item.qty} + {item.bonus}</div>
            <div className="text-xs text-gray-400">إجمالي: {item.totalUnits}</div>
        </td>
        <td className="p-3 font-mono text-sm">
            <div className="font-bold text-primary-700">{formatCurrency(item.netUnitCost)}</div>
            <div className="text-xs text-gray-400">الإجمالي: {formatCurrency(item.netTotalCost)}</div>
        </td>
        <td className="p-3 text-center">
            <span className={`inline-block font-bold px-2 py-1 rounded text-xs ${item.realDiscountPct > 25 ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700'}`}>
            {formatPercent(item.realDiscountPct)}
            </span>
        </td>
        <td className="p-3">
            <div className="flex justify-center gap-2">
                {item.isFakeDiscount && (
                    <div className="group relative">
                        <div className="bg-orange-100 text-orange-600 p-1.5 rounded-full cursor-help">
                            <AlertTriangle size={16} />
                        </div>
                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover:block bg-gray-800 text-white text-xs p-2 rounded whitespace-nowrap z-10 shadow-lg">
                            خصم وهمي: الخصم الحقيقي أقل بكثير من المتوقع
                        </div>
                    </div>
                )}
                {item.historyComparison !== 'new' && item.historyComparison && (
                    <div className="group relative">
                        <div className={`p-1.5 rounded-full cursor-help ${
                            item.historyComparison === 'better' ? 'bg-green-100 text-green-600' :
                            item.historyComparison === 'worse' ? 'bg-red-100 text-red-600' :
                            'bg-gray-100 text-gray-600'
                        }`}>
                            {item.historyComparison === 'better' && <TrendingDown size={16} />}
                            {item.historyComparison === 'worse' && <TrendingUp size={16} />}
                            {item.historyComparison === 'same' && <Minus size={16} />}
                        </div>
                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover:block bg-gray-800 text-white text-xs p-2 rounded whitespace-nowrap z-10 shadow-lg">
                            {item.historyComparison === 'better' && `سعر أفضل بـ ${formatPercent(item.priceDifferencePct || 0)} عن آخر مرة`}
                            {item.historyComparison === 'worse' && `سعر أغلى بـ ${formatPercent(item.priceDifferencePct || 0)} عن آخر مرة`}
                            {item.historyComparison === 'same' && 'نفس سعر الشراء السابق'}
                        </div>
                    </div>
                )}
            </div>
        </td>
        <td className="p-3 no-print text-center">
            <button onClick={() => onRemove(item.id)} className="text-red-400 hover:text-red-600 transition-colors p-1 hover:bg-red-50 rounded">
            <Trash2 size={16} />
            </button>
        </td>
    </tr>
);

const Calculator: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [currentInput, setCurrentInput] = useState<ItemInput>(INITIAL_INPUT);
  const [invoiceItems, setInvoiceItems] = useState<CalculatedItem[]>([]);
  const [showInvoiceSaved, setShowInvoiceSaved] = useState(false);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [knownItemNames, setKnownItemNames] = useState<string[]>([]);
  const [selectedSupplierId, setSelectedSupplierId] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [lastHistoryItem, setLastHistoryItem] = useState<CalculatedItem | null>(null);
  const [bonusSuggestion, setBonusSuggestion] = useState<CalculatedItem | null>(null);
  const [editingInvoiceId, setEditingInvoiceId] = useState<string | null>(null);

  useEffect(() => {
    setSettings(StorageService.getSettings());
    setSuppliers(StorageService.getSuppliers());
    setKnownItemNames(StorageService.getAllItemNames());

    // Check for Edit Mode
    if (location.state && location.state.editInvoice) {
        const inv = location.state.editInvoice as Invoice;
        setEditingInvoiceId(inv.id);
        setInvoiceItems(inv.items);
        setInvoiceNumber(inv.invoiceNumber || '');
        setSelectedSupplierId(inv.supplierId || '');
        // Clear state to avoid reload issues
        window.history.replaceState({}, document.title);
    }
  }, [location.state]);

  useEffect(() => {
    if (currentInput.name.length > 1) {
        // 1. Try to find in Catalog first for price autofill
        const catalogItem = StorageService.getCatalogItemByName(currentInput.name);

        // إذا وجدنا الصنف في الدليل، نقوم بتحديث البيانات فوراً حتى لو كانت الحقول ممتلئة سابقاً
        // يتم التحقق من اختلاف القيم لتجنب إعادة الرسم غير الضرورية
        if (catalogItem) {
            if (currentInput.type !== catalogItem.type || 
                currentInput.publicPrice !== catalogItem.publicPrice || 
                currentInput.pharmaPrice !== catalogItem.pharmaPrice) {

                setCurrentInput(prev => ({ 
                    ...prev, 
                    type: catalogItem.type, 
                    publicPrice: catalogItem.publicPrice,
                    pharmaPrice: catalogItem.pharmaPrice 
                }));
            }
        }

        // 2. History & Bonus logic
        const history = StorageService.getLastPurchaseItem(currentInput.name);
        setLastHistoryItem(history);
        if (currentInput.bonus === 0 && currentInput.qty > 0) {
            const bonusItem = StorageService.getItemWithBonusHistory(currentInput.name);
            if (bonusItem && bonusItem.qty > currentInput.qty) {
                setBonusSuggestion(bonusItem);
            } else {
                setBonusSuggestion(null);
            }
        } else {
            setBonusSuggestion(null);
        }
    } else {
        setLastHistoryItem(null);
        setBonusSuggestion(null);
    }
  }, [currentInput.name, currentInput.qty, currentInput.bonus]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setCurrentInput(prev => ({
      ...prev,
      [name]: (name === 'name' || name === 'type' || name === 'taxMethod') 
        ? value 
        : parseFloat(value) || 0
    }));
  };

  const handleTaxCheck = () => {
    setCurrentInput(prev => ({
        ...prev,
        taxMethod: prev.taxMethod === TaxMethod.PER_UNIT ? TaxMethod.TOTAL : TaxMethod.PER_UNIT
    }));
  };

  const getEffectiveDiscount = (): number => {
    if (selectedSupplierId) {
        const supplier = suppliers.find(s => s.id === selectedSupplierId);
        if (supplier) {
            if (currentInput.type === ItemType.NORMAL && supplier.discountNormal !== undefined) return supplier.discountNormal;
            if (currentInput.type === ItemType.SPECIAL && supplier.discountSpecial !== undefined) return supplier.discountSpecial;
            if (currentInput.type === ItemType.OTHER && supplier.discountOther !== undefined) return supplier.discountOther;
        }
    }
    return -1;
  };

  const addItem = () => {
    if (!currentInput.name || (currentInput.pharmaPrice <= 0 && currentInput.publicPrice <= 0)) {
      alert('الرجاء إدخال اسم الصنف والسعر');
      return;
    }

    const effectiveDiscount = getEffectiveDiscount();
    const itemToCalc = {
        ...currentInput, 
        id: Date.now().toString() + Math.random(),
        customTypeDiscount: effectiveDiscount >= 0 ? effectiveDiscount : undefined
    };

    const calculated = CalculatorService.calculateItem(itemToCalc, settings);
    setInvoiceItems([...invoiceItems, calculated]);
    setCurrentInput({ ...INITIAL_INPUT, type: currentInput.type }); 
    setLastHistoryItem(null);
    setBonusSuggestion(null);
  };

  const removeItem = (id: string) => {
    setInvoiceItems(invoiceItems.filter(i => i.id !== id));
  };

  const saveInvoice = () => {
    if (invoiceItems.length === 0) return;
    if (!selectedSupplierId) {
        alert('تنبيه: لا يمكن حفظ الفاتورة بدون اختيار مورد.');
        return;
    }
    const supplierObj = suppliers.find(s => s.id === selectedSupplierId);
    const totalValue = invoiceItems.reduce((sum, item) => sum + item.netTotalCost, 0);

    // Preserve Original Date if Editing, else new Date
    const originalInvoice = editingInvoiceId ? StorageService.getInvoiceById(editingInvoiceId) : null;

    const invoice: Invoice = {
      id: editingInvoiceId || Date.now().toString(),
      date: originalInvoice ? originalInvoice.date : new Date().toISOString(),
      invoiceNumber,
      supplierId: selectedSupplierId,
      supplierName: supplierObj ? supplierObj.name : 'غير محدد',
      items: invoiceItems,
      totalValue,
      totalItems: invoiceItems.length,
      totalUnits: invoiceItems.reduce((sum, item) => sum + item.totalUnits, 0),
      isSold: originalInvoice ? originalInvoice.isSold : false
    };

    StorageService.saveInvoice(invoice);
    setKnownItemNames(StorageService.getAllItemNames());
    setShowInvoiceSaved(true);

    // Reset or Navigate back
    if (editingInvoiceId) {
        setTimeout(() => navigate('/invoices'), 1500);
    } else {
        setInvoiceItems([]);
        // تم تحديث الكود: عدم مسح المورد ليظل مختاراً للفاتورة التالية
        // setSelectedSupplierId(''); 
        setInvoiceNumber('');
        setTimeout(() => setShowInvoiceSaved(false), 3000);
    }
  };

  const groupedItems = useMemo(() => {
    const groups: Partial<Record<ItemType, CalculatedItem[]>> = {
        [ItemType.NORMAL]: [],
        [ItemType.SPECIAL]: [],
        [ItemType.OTHER]: []
    };
    invoiceItems.forEach(item => {
        if (groups[item.type]) groups[item.type]?.push(item);
        else groups[ItemType.OTHER]?.push(item);
    });
    return groups;
  }, [invoiceItems]);

  const currentSupplierName = suppliers.find(s => s.id === selectedSupplierId)?.name || '';

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
      <div className="lg:col-span-4 space-y-4 no-print">

        {editingInvoiceId && (
            <div className="bg-blue-50 border border-blue-200 p-4 rounded-xl flex items-center justify-between">
                <span className="text-blue-700 font-bold flex items-center gap-2"><ArrowLeft size={18} /> وضع تعديل الفاتورة</span>
                <button onClick={() => navigate('/invoices')} className="text-xs underline text-blue-500">عودة</button>
            </div>
        )}

        <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 space-y-3">
             <div className="flex items-center gap-2 mb-2 text-primary-700 font-bold border-b pb-2">
                <User size={18} />
                <span>بيانات الفاتورة والمورد</span>
             </div>
             <div>
                <label className="text-xs font-semibold text-gray-500 mb-1 block">اسم المورد *</label>
                <select value={selectedSupplierId} onChange={(e) => setSelectedSupplierId(e.target.value)} className={`w-full p-2 border rounded-lg bg-gray-50 ${!selectedSupplierId ? 'border-orange-300 bg-orange-50' : 'border-green-300 bg-green-50'}`}>
                    <option value="">-- اختر مورد لتطبيق خصوماته --</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
             </div>
             <div>
                <label className="text-xs font-semibold text-gray-500 mb-1 block">رقم الفاتورة الورقية</label>
                <input type="text" value={invoiceNumber} onChange={(e) => setInvoiceNumber(e.target.value)} placeholder="مثال: 10255" className="w-full p-2 border rounded-lg bg-gray-50" />
             </div>
        </div>

        <div className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                <Plus className="text-primary-600" /> إضافة صنف
            </h2>
            <button 
                onClick={saveInvoice} 
                disabled={invoiceItems.length === 0}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold flex items-center gap-1 transition-colors ${invoiceItems.length > 0 ? 'bg-green-600 text-white hover:bg-green-700 shadow-sm' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
            >
                <Save size={14} /> حفظ سريع
            </button>
          </div>
          <div className="space-y-4">
            <div className="flex gap-2">
                <div className="flex-1 relative">
                    <label className="text-xs font-semibold text-gray-500 block mb-1">اسم الصنف</label>
                    <input list="item-names" name="name" value={currentInput.name} onChange={handleInputChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-primary-500" placeholder="ابحث..." autoComplete="off" />
                    <datalist id="item-names">
                        {knownItemNames.map((n, i) => <option key={i} value={n} />)}
                    </datalist>
                </div>
                <div className="w-24">
                     <label className="text-xs font-semibold text-gray-500 block mb-1">النوع</label>
                     <select name="type" value={currentInput.type} onChange={handleInputChange} className="w-full p-2 border rounded-lg bg-gray-50 text-sm">
                        {Object.entries(ItemTypeShort).map(([key, abbr]) => <option key={key} value={key}>{abbr}</option>)}
                     </select>
                </div>
            </div>

            {/* Display active discount context */}
            {selectedSupplierId && (
                <div className="text-xs text-green-600 bg-green-50 p-2 rounded flex justify-between items-center">
                    <span>خصم المورد النشط:</span>
                    <span className="font-bold">
                        {getEffectiveDiscount() >= 0 ? `${getEffectiveDiscount()}%` : 'افتراضي'}
                    </span>
                </div>
            )}

            <div className="space-y-2">
                {lastHistoryItem && (
                    <div className="bg-blue-50 border border-blue-100 rounded-lg p-3 flex items-start gap-2 text-sm text-blue-800 animate-fade-in">
                        <Info size={16} className="mt-0.5 shrink-0" />
                        <div><div className="font-bold">سجل سابق:</div><div>سعر الصافي: {formatCurrency(lastHistoryItem.netUnitCost)}</div><div>الخصم: {formatPercent(lastHistoryItem.realDiscountPct)}</div></div>
                    </div>
                )}
                {bonusSuggestion && (
                     <div className="bg-purple-50 border border-purple-100 rounded-lg p-3 flex items-start gap-2 text-sm text-purple-800 animate-fade-in cursor-pointer hover:bg-purple-100" onClick={() => setCurrentInput(prev => ({...prev, qty: bonusSuggestion.qty, bonus: bonusSuggestion.bonus}))}>
                        <Lightbulb size={16} className="mt-0.5 shrink-0 text-purple-600" />
                        <div><div className="font-bold mb-1">💡 نصيحة ذكية (اضغط للتطبيق)</div><div>سابقاً اشتريت {bonusSuggestion.qty} + {bonusSuggestion.bonus} بونص.</div></div>
                    </div>
                )}
            </div>
            <div className="flex gap-2">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">العدد</label><input type="number" name="qty" value={currentInput.qty} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">بونص</label><input type="number" name="bonus" value={currentInput.bonus} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex gap-2">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">سعر الجمهور</label><input type="number" name="publicPrice" value={currentInput.publicPrice} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">سعر الصيدلي</label><input type="number" name="pharmaPrice" value={currentInput.pharmaPrice} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex gap-2 items-end">
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">خ. مورد (قيمة)</label><input type="number" name="supplierDiscountVal" value={currentInput.supplierDiscountVal} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1"><label className="text-xs font-semibold text-gray-500 block mb-1">خ. إضافي %</label><input type="number" name="extraDiscountPct" value={currentInput.extraDiscountPct} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
                <div className="flex-1 relative"><label className="text-xs font-semibold text-gray-500 block mb-1">الضريبة</label><input type="number" name="taxValue" value={currentInput.taxValue} onChange={handleInputChange} className="w-full p-2 border rounded-lg" /></div>
            </div>
            <div className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer select-none" onClick={handleTaxCheck}>
                {currentInput.taxMethod === TaxMethod.TOTAL ? <CheckSquare size={18} className="text-primary-600" /> : <Square size={18} className="text-gray-400" />}
                <span>الضريبة مبلغ كلي</span>
            </div>
            <button onClick={addItem} className="w-full bg-primary-600 hover:bg-primary-700 text-white font-bold py-3 rounded-xl shadow-lg mt-2">حساب وإضافة</button>
          </div>
        </div>
      </div>
      <div className="lg:col-span-8 space-y-4">

        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-4 border-b bg-gray-50 flex justify-between items-center">
            <h3 className="font-bold text-gray-700 flex items-center gap-2"><ShoppingCart size={20} /> مسودة الفاتورة {currentSupplierName && ` - ${currentSupplierName}`}</h3>
            <div className="text-sm text-gray-500">{invoiceItems.length} أصناف</div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-gray-50 text-gray-500 text-xs uppercase"><tr><th className="p-3">الصنف</th><th className="p-3">العدد</th><th className="p-3">الصافي</th><th className="p-3 text-center">خصم حقيقي</th><th className="p-3 text-center">تحليل</th><th className="p-3 no-print"></th></tr></thead>
              <tbody className="divide-y divide-gray-100">
                {Object.entries(groupedItems).map(([type, items]) => {
                    const typedItems = items as CalculatedItem[];
                    if (!typedItems || typedItems.length === 0) return null;
                    return (
                        <React.Fragment key={type}>
                            <tr className="bg-primary-50 border-y border-primary-100"><td colSpan={6} className="p-2 px-4 font-bold text-primary-700">{type}</td></tr>
                            {typedItems.map(item => <ItemRow key={item.id} item={item} onRemove={removeItem} />)}
                        </React.Fragment>
                    );
                })}
                {invoiceItems.length === 0 && <tr><td colSpan={6} className="p-8 text-center text-gray-400">لا توجد أصناف مضافة.</td></tr>}
              </tbody>
              <tfoot className="bg-gray-800 text-white font-bold"><tr><td colSpan={2} className="p-4 text-lg">الإجمالي النهائي</td><td colSpan={4} className="p-4 text-2xl text-left">{formatCurrency(invoiceItems.reduce((acc, i) => acc + i.netTotalCost, 0))}</td></tr></tfoot>
            </table>
          </div>
        </div>
        {invoiceItems.length > 0 && (
            <div className="flex justify-end gap-4 no-print">
                <button onClick={() => { setInvoiceItems([]); setEditingInvoiceId(null); navigate('/invoices'); }} className="px-6 py-3 rounded-xl border border-red-200 text-red-600">إلغاء</button>
                <button onClick={saveInvoice} className="bg-green-600 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2"><Save size={20} /> {editingInvoiceId ? 'حفظ التعديلات' : 'حفظ الفاتورة'}</button>
            </div>
        )}
        {showInvoiceSaved && <div className="fixed bottom-6 left-6 bg-green-600 text-white p-4 rounded-xl shadow-xl flex items-center gap-3 animate-bounce z-50"><Save size={24} /> {editingInvoiceId ? 'تم تحديث الفاتورة' : 'تم حفظ الفاتورة'}</div>}
      </div>
    </div>
  );
};

export default Calculator;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { StorageService } from '../services/storageService';
import { CalculatorService } from '../services/calculatorService';
import { Invoice, Client, ItemType, ClientTransaction, Supplier, ItemInput } from '../types';
import { FileText, Calendar, Package, ChevronDown, ChevronUp, Printer, Trash, Repeat, X, Check, Lock, UserCheck, ToggleLeft, ToggleRight, Edit } from 'lucide-react';

const Invoices: React.FC = () => {
  const navigate = useNavigate();
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [clients, setClients] = useState<Client[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [printInvoice, setPrintInvoice] = useState<Invoice | null>(null);

  // Resell Modal State
  const [showResellModal, setShowResellModal] = useState(false);
  const [resellInvoice, setResellInvoice] = useState<Invoice | null>(null);
  const [includeExtraDiscount, setIncludeExtraDiscount] = useState(false);
  const [resellConfig, setResellConfig] = useState({
      clientId: '',
      discountReg: 0,
      discountSpe: 0,
      discountOth: 0
  });

  useEffect(() => {
    setInvoices(StorageService.getInvoices());
    setClients(StorageService.getClients());
    setSuppliers(StorageService.getSuppliers());
  }, []);

  // Logic to apply Client discounts based on selection
  useEffect(() => {
    if (resellConfig.clientId) {
        const client = clients.find(c => c.id === resellConfig.clientId);
        const globalSettings = StorageService.getSettings();

        // Logic: Client Discount OR Global Settings
        setResellConfig(prev => ({
            ...prev,
            discountReg: client?.discountNormal ?? globalSettings.discountNormal,
            discountSpe: client?.discountSpecial ?? globalSettings.discountSpecial,
            discountOth: client?.discountOther ?? globalSettings.discountOther,
        }));
    }
  }, [resellConfig.clientId]);

  const toggleExpand = (id: string) => setExpandedId(expandedId === id ? null : id);

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('هل أنت متأكد من حذف هذه الفاتورة؟')) {
      StorageService.deleteInvoice(id);
      setInvoices(StorageService.getInvoices());
    }
  };

  const handleEdit = (invoice: Invoice, e: React.MouseEvent) => {
      e.stopPropagation();
      if (invoice.isSold) {
          alert('لا يمكن تعديل فاتورة تم بيعها أو توزيعها.');
          return;
      }
      // Navigate to Calculator with Invoice Data
      navigate('/calculator', { state: { editInvoice: invoice } });
  };

  const handlePrint = (invoice: Invoice, e: React.MouseEvent) => {
    e.stopPropagation();
    setPrintInvoice(invoice);
    setTimeout(() => { window.print(); }, 100);
  };

  const openResellModal = (invoice: Invoice, e: React.MouseEvent) => {
      e.stopPropagation();
      if (invoice.isSold) return;
      setResellInvoice(invoice);
      setResellConfig({ clientId: '', discountReg: 0, discountSpe: 0, discountOth: 0 });
      setIncludeExtraDiscount(false);
      setShowResellModal(true);
  };

  const calculateSellTotal = () => {
      if (!resellInvoice) return 0;

      const globalSettings = StorageService.getSettings();
      let total = 0;

      resellInvoice.items.forEach(item => {
          let clientDiscountPct = 0;
          if (item.type === ItemType.NORMAL) clientDiscountPct = resellConfig.discountReg;
          else if (item.type === ItemType.SPECIAL) clientDiscountPct = resellConfig.discountSpe;
          else clientDiscountPct = resellConfig.discountOth;

          const input: ItemInput = {
              ...item,
              customTypeDiscount: clientDiscountPct,
              extraDiscountPct: includeExtraDiscount ? item.extraDiscountPct : 0,
              supplierDiscountVal: item.supplierDiscountVal
          };

          const result = CalculatorService.calculateItem(input, globalSettings);
          total += result.netTotalCost;
      });

      return total;
  };

  const confirmResell = () => {
      if (!resellConfig.clientId) return alert('اختر العميل');
      if (!resellInvoice) return;

      const totalAmount = calculateSellTotal();
      const transaction: ClientTransaction = {
          id: Date.now().toString(),
          clientId: resellConfig.clientId,
          date: new Date().toISOString(),
          type: 'SALE',
          amount: totalAmount,
          notes: `توزيع فاتورة #${resellInvoice.invoiceNumber || resellInvoice.id.slice(-4)} | خصومات: ${resellConfig.discountReg}%/${resellConfig.discountSpe}% | ${includeExtraDiscount ? 'مع خصم إضافي' : 'بدون إضافي'}`,
          relatedInvoiceId: resellInvoice.id,
          invoiceNumber: resellInvoice.invoiceNumber || resellInvoice.id.slice(-4)
      };

      StorageService.addTransaction(transaction);
      StorageService.markInvoiceAsSold(resellInvoice.id, resellConfig.clientId);

      alert('تم التوزيع بنجاح');
      setShowResellModal(false);
      setInvoices(StorageService.getInvoices());
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">سجل الفواتير</h2>
          <p className="text-gray-500 mt-1">إدارة المشتريات وعمليات التوزيع للعملاء</p>
        </div>
        <div className="bg-primary-50 text-primary-700 px-4 py-2 rounded-lg font-bold">
            {invoices.length} فاتورة
        </div>
      </div>

      <div className="space-y-4">
        {invoices.map((inv) => (
            <div key={inv.id} className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden transition-all">
                <div onClick={() => toggleExpand(inv.id)} className="p-4 flex flex-col md:flex-row md:items-center justify-between cursor-pointer hover:bg-gray-50 gap-4">
                    <div className="flex items-start md:items-center gap-4">
                        <div className="bg-primary-100 p-3 rounded-full text-primary-600 hidden md:block"><FileText size={24} /></div>
                        <div>
                            <div className="flex flex-wrap items-center gap-2 mb-1">
                                <div className="font-bold text-gray-800 text-lg">{inv.supplierName || 'غير محدد'}</div>
                                {inv.invoiceNumber && <span className="text-xs bg-gray-100 px-2 py-0.5 rounded border">#{inv.invoiceNumber}</span>}
                                {inv.isSold && <span className="text-xs bg-purple-100 text-purple-700 px-2 py-0.5 rounded border border-purple-200 font-bold flex items-center gap-1"><UserCheck size={12} /> تم التوزيع</span>}
                            </div>
                            <div className="text-sm text-gray-500 flex flex-wrap items-center gap-3">
                                <span className="flex items-center gap-1"><Calendar size={14} /> {new Date(inv.date).toLocaleDateString('ar-EG')}</span>
                                <span className="flex items-center gap-1"><Package size={14} /> {inv.totalItems} أصناف</span>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className="text-xl font-bold text-primary-700 bg-primary-50 px-3 py-1 rounded-lg">
                            {new Intl.NumberFormat('ar-EG', { style: 'currency', currency: 'EGP' }).format(inv.totalValue)}
                        </div>
                        {expandedId === inv.id ? <ChevronUp size={20} className="text-gray-400" /> : <ChevronDown size={20} className="text-gray-400" />}
                    </div>
                </div>

                {expandedId === inv.id && (
                    <div className="border-t border-gray-100 bg-gray-50 p-6 animate-fade-in">
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-right bg-white rounded-xl shadow-sm border">
                                <thead className="bg-gray-100 text-gray-600">
                                    <tr><th className="p-3">الصنف</th><th className="p-3">العدد</th><th className="p-3">سعر الجمهور</th><th className="p-3">الخصم</th><th className="p-3">الإجمالي</th></tr>
                                </thead>
                                <tbody className="divide-y">
                                    {inv.items.map((item, idx) => (
                                        <tr key={idx}>
                                            <td className="p-3 font-medium">{item.name}</td>
                                            <td className="p-3">{item.totalUnits}</td>
                                            <td className="p-3">{item.publicPrice.toFixed(2)}</td>
                                            <td className="p-3 text-green-600 font-bold">{item.realDiscountPct.toFixed(3)}%</td>
                                            <td className="p-3 font-bold">{item.netTotalCost.toFixed(2)}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>

                        <div className="flex justify-end gap-3 mt-6">
                            {inv.isSold ? (
                                <div className="flex items-center gap-2 bg-gray-100 text-gray-500 px-4 py-2 rounded-lg border"><Lock size={18} /> تم البيع</div>
                            ) : (
                                <>
                                  <button onClick={(e) => openResellModal(inv, e)} className="flex items-center gap-2 bg-purple-600 text-white px-6 py-2 rounded-lg hover:bg-purple-700 shadow-md"><Repeat size={18} /> بيع وتوزيع</button>
                                  <button onClick={(e) => handleEdit(inv, e)} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"><Edit size={18} /> تعديل</button>
                                </>
                            )}
                            <button onClick={(e) => handlePrint(inv, e)} className="flex items-center gap-2 bg-gray-800 text-white px-4 py-2 rounded-lg hover:bg-gray-900"><Printer size={18} /> طباعة</button>
                            <button onClick={(e) => handleDelete(inv.id, e)} className="flex items-center gap-2 text-red-600 hover:bg-red-50 px-4 py-2 rounded-lg"><Trash size={18} /> حذف</button>
                        </div>
                    </div>
                )}
            </div>
        ))}
      </div>

      {/* Resell Modal */}
      {showResellModal && (
          <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl overflow-hidden animate-scale-in">
                  <div className="p-5 border-b flex justify-between items-center bg-purple-600 text-white">
                      <h3 className="font-bold text-lg">توزيع الفاتورة لعميل</h3>
                      <button onClick={() => setShowResellModal(false)}><X /></button>
                  </div>
                  <div className="p-6 space-y-5">
                      <div>
                          <label className="block text-sm font-bold text-gray-700 mb-2">اختر العميل</label>
                          <select className="w-full p-3 border-2 border-gray-100 rounded-xl outline-none focus:border-purple-500 transition-all" value={resellConfig.clientId} onChange={e => setResellConfig({...resellConfig, clientId: e.target.value})}>
                              <option value="">-- اختر عميل من القائمة --</option>
                              {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                          </select>
                      </div>

                      <div className="grid grid-cols-3 gap-3">
                          <div><label className="text-xs font-bold text-gray-500 block mb-1">عادي %</label><input type="number" className="w-full p-2 border rounded-lg text-center font-bold" value={resellConfig.discountReg} onChange={e => setResellConfig({...resellConfig, discountReg: parseFloat(e.target.value) || 0})} /></div>
                          <div><label className="text-xs font-bold text-gray-500 block mb-1">خاص %</label><input type="number" className="w-full p-2 border rounded-lg text-center font-bold" value={resellConfig.discountSpe} onChange={e => setResellConfig({...resellConfig, discountSpe: parseFloat(e.target.value) || 0})} /></div>
                          <div><label className="text-xs font-bold text-gray-500 block mb-1">أخرى %</label><input type="number" className="w-full p-2 border rounded-lg text-center font-bold" value={resellConfig.discountOth} onChange={e => setResellConfig({...resellConfig, discountOth: parseFloat(e.target.value) || 0})} /></div>
                      </div>

                      <div className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl border border-gray-100">
                          <div className="flex items-center gap-2">
                             <span className="text-sm font-bold text-gray-700">تضمين الخصم الإضافي؟</span>
                             <button onClick={() => setIncludeExtraDiscount(!includeExtraDiscount)} className="text-purple-600">
                                {includeExtraDiscount ? <ToggleRight size={36} /> : <ToggleLeft size={36} className="text-gray-300" />}
                             </button>
                          </div>
                          <span className="text-xs text-gray-400 max-w-[150px] leading-tight text-left">سيتم إضافة نسبة الخصم الإضافي من الفاتورة الأصلية للعميل أيضاً</span>
                      </div>

                      <div className="bg-purple-50 p-6 rounded-2xl text-center border-2 border-purple-100">
                          <div className="text-xs text-purple-600 font-bold mb-1">قيمة المديونية النهائية على العميل</div>
                          <div className="text-4xl font-black text-purple-700">
                              {new Intl.NumberFormat('ar-EG', { style: 'currency', currency: 'EGP' }).format(calculateSellTotal())}
                          </div>
                      </div>

                      <button onClick={confirmResell} className="w-full bg-purple-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-purple-500/30 hover:bg-purple-700 transition-all flex items-center justify-center gap-2"><Check /> تسجيل المديونية وتأكيد التوزيع</button>
                  </div>
              </div>
          </div>
      )}

      {/* Hidden Print Area */}
      <div id="printable-area" style={{ display: 'none' }}>
        {printInvoice && (
             <div className="p-8 font-sans" dir="rtl">
                <h1 className="text-2xl font-bold mb-4 border-b pb-2">فاتورة مشتريات صيدلية</h1>
                <p><strong>المورد:</strong> {printInvoice.supplierName}</p>
                <p><strong>التاريخ:</strong> {new Date(printInvoice.date).toLocaleString('ar-EG')}</p>
                <table className="w-full mt-6 border-collapse border">
                    <thead><tr className="bg-gray-100"><th>الصنف</th><th>العدد</th><th>سعر الجمهور</th><th>الخصم</th><th>الإجمالي</th></tr></thead>
                    <tbody>
                        {printInvoice.items.map((item, i) => (
                            <tr key={i} className="border"><td className="p-2">{item.name}</td><td className="p-2">{item.totalUnits}</td><td className="p-2">{item.publicPrice.toFixed(2)}</td><td className="p-2">{item.realDiscountPct.toFixed(3)}%</td><td className="p-2 font-bold">{item.netTotalCost.toFixed(2)}</td></tr>
                        ))}
                    </tbody>
                </table>
                <div className="mt-8 text-right font-bold text-xl">الإجمالي: {printInvoice.totalValue.toFixed(2)} EGP</div>
            </div>
        )}
      </div>
    </div>
  );
};

