      localStorage.setItem(KEYS.SETTINGS, encrypt(PRELOADED_DATA.settings));
      localStorage.setItem(KEYS.SUPPLIERS, encrypt(PRELOADED_DATA.suppliers));
      localStorage.setItem(KEYS.CLIENTS, encrypt(PRELOADED_DATA.clients));
      localStorage.setItem(KEYS.INVOICES, encrypt(PRELOADED_DATA.invoices));
      localStorage.setItem(KEYS.TRANSACTIONS, encrypt(PRELOADED_DATA.transactions));
      localStorage.setItem(KEYS.CATALOG, encrypt(PRELOADED_DATA.catalog));
      window.location.reload();
  },

  getSettings: (): AppSettings => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.SETTINGS));
      if (data) {
        if (!data.users || data.users.length === 0) data.users = [DEFAULT_SETTINGS.users[0]];
        return data;
      }
      return PRELOADED_DATA.settings; // Fallback to preloaded
    } catch (e) { return PRELOADED_DATA.settings; }
  },

  saveSettings: (settings: AppSettings): void => {
    localStorage.setItem(KEYS.SETTINGS, encrypt(settings));
  },

  getCurrentUser: (): User | null => {
      const userStr = sessionStorage.getItem('current_user');
      return userStr ? JSON.parse(userStr) : null;
  },

  getCatalog: (): ItemCatalogEntry[] => {
      try {
          const data = decrypt(localStorage.getItem(KEYS.CATALOG));
          return data || PRELOADED_DATA.catalog;
      } catch { return PRELOADED_DATA.catalog; }
  },

  saveCatalogItem: (item: ItemCatalogEntry): void => {
      const list = StorageService.getCatalog();
      const idx = list.findIndex(i => i.id === item.id);
      if (idx >= 0) list[idx] = item;
      else list.push(item);
      localStorage.setItem(KEYS.CATALOG, encrypt(list));
  },

  deleteCatalogItem: (id: string): void => {
      const list = StorageService.getCatalog();
      const updated = list.filter(i => i.id !== id);
      localStorage.setItem(KEYS.CATALOG, encrypt(updated));
  },

  importCatalog: (items: ItemCatalogEntry[]): void => {
      const current = StorageService.getCatalog();
      items.forEach(newItem => {
          const existingIdx = current.findIndex(c => c.name.trim().toLowerCase() === newItem.name.trim().toLowerCase());
          if (existingIdx >= 0) {
              current[existingIdx] = { ...current[existingIdx], ...newItem, id: current[existingIdx].id };
          } else {
              current.push({ ...newItem, id: Date.now().toString() + Math.random() });
          }
      });
      localStorage.setItem(KEYS.CATALOG, encrypt(current));
  },

  getSuppliers: (): Supplier[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.SUPPLIERS));
      return data || PRELOADED_DATA.suppliers;
    } catch (e) { return PRELOADED_DATA.suppliers; }
  },

  saveSupplier: (supplier: Supplier): void => {
    const list = StorageService.getSuppliers();
    const existingIndex = list.findIndex(s => s.id === supplier.id);
    if (existingIndex >= 0) {
        list[existingIndex] = supplier;
    } else {
        list.push(supplier);
    }
    localStorage.setItem(KEYS.SUPPLIERS, encrypt(list));
  },

  deleteSupplier: (id: string): void => {
    const list = StorageService.getSuppliers();
    const updated = list.filter(s => s.id !== id);
    localStorage.setItem(KEYS.SUPPLIERS, encrypt(updated));
  },

  getClients: (): Client[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.CLIENTS));
      return data || PRELOADED_DATA.clients;
    } catch (e) { return PRELOADED_DATA.clients; }
  },

  saveClient: (client: Client): void => {
    const list = StorageService.getClients();
    const existingIndex = list.findIndex(c => c.id === client.id);
    if (existingIndex >= 0) {
        list[existingIndex] = client;
    } else {
        list.push(client);
    }
    localStorage.setItem(KEYS.CLIENTS, encrypt(list));
  },

  deleteClient: (id: string): void => {
    const list = StorageService.getClients();
    const updated = list.filter(c => c.id !== id);
    localStorage.setItem(KEYS.CLIENTS, encrypt(updated));
  },

  getTransactions: (clientId?: string): ClientTransaction[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.TRANSACTIONS));
      const all = data || PRELOADED_DATA.transactions;
      if (clientId) {
        return all.filter((t: ClientTransaction) => t.clientId === clientId).sort((a: any, b: any) => new Date(b.date).getTime() - new Date(a.date).getTime());
      }
      return all;
    } catch (e) { return []; }
  },

  addTransaction: (transaction: ClientTransaction): void => {
    const transactions = StorageService.getTransactions();
    transactions.push(transaction);
    localStorage.setItem(KEYS.TRANSACTIONS, encrypt(transactions));

    const clients = StorageService.getClients();
    const clientIndex = clients.findIndex(c => c.id === transaction.clientId);
    if (clientIndex >= 0) {
        const client = clients[clientIndex];
        if (transaction.type === 'SALE') {
            client.balance += transaction.amount;
        } else {
            client.balance -= transaction.amount;
        }
        clients[clientIndex] = client;
        localStorage.setItem(KEYS.CLIENTS, encrypt(clients));
    }
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.INVOICES));
      if (!data || data.length === 0) return PRELOADED_DATA.invoices;
      return data;
    } catch (e) { return PRELOADED_DATA.invoices; }
  },

  getInvoiceById: (id: string): Invoice | undefined => {
      return StorageService.getInvoices().find(i => i.id === id);
  },

  saveInvoice: (invoice: Invoice): void => {
    const invoices = StorageService.getInvoices();
    const index = invoices.findIndex(i => i.id === invoice.id);

    if (index >= 0) {
        invoices[index] = invoice;
    } else {
        invoices.unshift(invoice);
    }
    localStorage.setItem(KEYS.INVOICES, encrypt(invoices));

    const catalog = StorageService.getCatalog();
    let catalogChanged = false;
    invoice.items.forEach(item => {
        if (!catalog.some(c => c.name.trim().toLowerCase() === item.name.trim().toLowerCase())) {
            catalog.push({
                id: Date.now().toString() + Math.random(),
                name: item.name,
                type: item.type,
                publicPrice: item.publicPrice,
                pharmaPrice: item.pharmaPrice
            });
            catalogChanged = true;
        }
    });
    if (catalogChanged) localStorage.setItem(KEYS.CATALOG, encrypt(catalog));
  },

  markInvoiceAsSold: (invoiceId: string, clientId: string): void => {
    const invoices = StorageService.getInvoices();
    const index = invoices.findIndex(inv => inv.id === invoiceId);
    if (index >= 0) {
        invoices[index].isSold = true;
        invoices[index].soldToClientId = clientId;
        invoices[index].soldDate = new Date().toISOString();
        localStorage.setItem(KEYS.INVOICES, encrypt(invoices));
    }
  },

  deleteInvoice: (id: string): void => {
    const invoices = StorageService.getInvoices();
    const updated = invoices.filter(inv => inv.id !== id);
    localStorage.setItem(KEYS.INVOICES, encrypt(updated));
  },

  getLastPurchaseItem: (itemName: string): CalculatedItem | null => {
    const invoices = StorageService.getInvoices();
    for (const inv of invoices) {
      const found = inv.items.find(item => item.name.trim().toLowerCase() === itemName.trim().toLowerCase());
      if (found) return found;
    }
    return null;
  },

  getItemWithBonusHistory: (itemName: string): CalculatedItem | null => {
    const invoices = StorageService.getInvoices();
    for (const inv of invoices) {
      const found = inv.items.find(item => 
        item.name.trim().toLowerCase() === itemName.trim().toLowerCase() && 
        item.bonus > 0
      );
      if (found) return found;
    }
    return null;
  },

  getAllItemNames: (): string[] => {
    const catalogNames = StorageService.getCatalog().map(c => c.name);
    const invoiceNames = new Set<string>();
    StorageService.getInvoices().forEach(inv => {
        inv.items.forEach(item => invoiceNames.add(item.name));
    });
    return Array.from(new Set([...catalogNames, ...Array.from(invoiceNames)]));
  },

  getCatalogItemByName: (name: string): ItemCatalogEntry | undefined => {
      return StorageService.getCatalog().find(c => c.name.trim().toLowerCase() === name.trim().toLowerCase());
  },

  createBackup: (): string => {
      const backup = {
          settings: StorageService.getSettings(),
          suppliers: StorageService.getSuppliers(),
          clients: StorageService.getClients(),
          invoices: StorageService.getInvoices(),
          transactions: StorageService.getTransactions(),
          catalog: StorageService.getCatalog(),
          version: '2.1',
          date: new Date().toISOString()
      };
      return JSON.stringify(backup, null, 2);
  },

  restoreBackup: (jsonString: string): boolean => {
      try {
          if (!jsonString) return false;
          const cleanJson = jsonString.replace(/^\uFEFF/, '');
          const data = JSON.parse(cleanJson);

          if (!data || typeof data !== 'object') {
             console.error("Invalid backup format");
             return false;
          }

          if (data.settings) localStorage.setItem(KEYS.SETTINGS, encrypt(data.settings));
          if (data.suppliers) localStorage.setItem(KEYS.SUPPLIERS, encrypt(data.suppliers));
          if (data.clients) localStorage.setItem(KEYS.CLIENTS, encrypt(data.clients));
          if (data.invoices) localStorage.setItem(KEYS.INVOICES, encrypt(data.invoices));
          if (data.transactions) localStorage.setItem(KEYS.TRANSACTIONS, encrypt(data.transactions));
          if (data.catalog) localStorage.setItem(KEYS.CATALOG, encrypt(data.catalog));

          return true;
      } catch (e) {
          console.error("Restore Failed", e);
          return false;
      }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Save, RefreshCw, Download, Upload, Database, Check, User, ShieldCheck, Settings2, Image as ImageIcon, Plus, Trash2, FileJson } from 'lucide-react';
import { StorageService } from '../services/storageService';
import { AppSettings, DEFAULT_SETTINGS, User as UserType } from '../types';

const Settings: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [msg, setMsg] = useState('');
  const [newUser, setNewUser] = useState<UserType>({ id: '', username: '', password: '', fullName: '', role: 'user', permissions: [] });
  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { setSettings(StorageService.getSettings()); }, []);

  const handleSave = () => {
    StorageService.saveSettings(settings);
    setMsg('تم حفظ الإعدادات بنجاح');
    setTimeout(() => setMsg(''), 3000);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onloadend = () => {
              setSettings(prev => ({ ...prev, userAvatar: reader.result as string }));
          };
          reader.readAsDataURL(file);
      }
  };

  const handleAddUser = () => {
      if (!newUser.username || !newUser.password) return alert('اسم المستخدم وكلمة المرور مطلوبان');
      const updatedUsers = [...settings.users, { ...newUser, id: Date.now().toString(), permissions: newUser.role === 'admin' ? ['*'] : newUser.permissions }];
      setSettings(prev => ({ ...prev, users: updatedUsers }));
      setNewUser({ id: '', username: '', password: '', fullName: '', role: 'user', permissions: [] });
  };

  const handleRemoveUser = (userId: string) => {
      if (settings.users.length <= 1) return alert('لا يمكن حذف المستخدم الوحيد');
      setSettings(prev => ({ ...prev, users: prev.users.filter(u => u.id !== userId) }));
  };

  const handleQuickBackup = () => {
      const data = StorageService.createBackup();
      const fileName = `pharmamind_backup_${new Date().toISOString().split('T')[0]}.json`;
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = fileName;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setMsg('تم تحميل النسخة بنجاح');
      setTimeout(() => setMsg(''), 3000);
  };

  const handleSaveAsBackup = async () => {
    const data = StorageService.createBackup();
    const fileName = `pharmamind_backup_${new Date().toISOString().split('T')[0]}.json`;

    if ('showSaveFilePicker' in window) {
      try {
        const handle = await (window as any).showSaveFilePicker({
          suggestedName: fileName,
          types: [{ description: 'JSON Backup', accept: { 'application/json': ['.json'] } }],
        });
        const writable = await handle.createWritable();
        await writable.write(data);
        await writable.close();
        setMsg('تم حفظ النسخة بنجاح في المكان المختار');
      } catch (err) {
        console.error('User cancelled or error occurred', err);
      }
    } else {
      alert('متصفحك لا يدعم اختيار مكان الحفظ المباشر، سيتم استخدام التحميل العادي.');
      handleQuickBackup();
    }
    setTimeout(() => setMsg(''), 3000);
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          const content = event.target?.result as string;
          if (!content || content.trim() === '') {
              alert('الملف المختار فارغ أو تالف.');
              return;
          }

          if (StorageService.restoreBackup(content)) {
              setMsg('تم استعادة البيانات! جاري إعادة التحميل...');
              setTimeout(() => window.location.reload(), 2000);
          } else {
              alert('فشل استعادة الملف. تأكد من أن الملف بصيغة JSON صحيح ولم يتم تعديله يدوياً.');
          }
      };
      reader.onerror = () => alert('حدث خطأ أثناء قراءة الملف.');
      reader.readAsText(file);
      e.target.value = '';
  };

  const handleForceFactoryReset = () => {
      if(window.confirm('هل أنت متأكد من استعادة البيانات الأصلية؟ سيتم مسح أي تعديلات جديدة والعودة لبياناتك المحفوظة مسبقاً.')) {
          StorageService.factoryReset();
      }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-8">
        <h2 className="text-2xl font-bold mb-8 text-gray-800 flex items-center gap-2"><Settings2 className="text-primary-600" /> إعدادات النظام والأمان</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-4">
             <h3 className="font-bold text-gray-700 flex items-center gap-2 border-b pb-2"><User size={18} className="text-blue-500" /> مظهر التطبيق</h3>
             <div><label className="block text-xs font-bold text-gray-500 mb-1">اسم الصيدلية</label><input type="text" value={settings.pharmacyName} onChange={(e) => setSettings({...settings, pharmacyName: e.target.value})} className="w-full p-3 border rounded-xl" /></div>
             <div><label className="block text-xs font-bold text-gray-500 mb-1">نص اللوجو (شاشة الدخول)</label><input type="text" value={settings.logoText || ''} onChange={(e) => setSettings({...settings, logoText: e.target.value})} className="w-full p-3 border rounded-xl" placeholder="Abdullah Mohsin" /></div>

             <div>
                <label className="block text-xs font-bold text-gray-500 mb-2">شعار / صورة الملف الشخصي</label>
                <div className="flex items-center gap-4">
                    <div className="w-16 h-16 rounded-full bg-gray-100 border overflow-hidden">
                        {settings.userAvatar ? <img src={settings.userAvatar} className="w-full h-full object-cover" /> : <User className="w-full h-full p-4 text-gray-300" />}
                    </div>
                    <input type="file" ref={imageInputRef} accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <button onClick={() => imageInputRef.current?.click()} className="text-sm bg-gray-50 border px-3 py-2 rounded-lg hover:bg-gray-100 flex items-center gap-1"><ImageIcon size={14} /> اختر صورة</button>
                    {settings.userAvatar && <button onClick={() => setSettings({...settings, userAvatar: undefined})} className="text-sm text-red-500 hover:text-red-700">حذف</button>}
                </div>
             </div>
          </div>

          <div className="space-y-4">
             <h3 className="font-bold text-gray-700 flex items-center gap-2 border-b pb-2"><ShieldCheck size={18} className="text-green-500" /> إدارة المستخدمين</h3>

             <div className="bg-gray-50 p-4 rounded-xl space-y-3 border border-gray-200">
                 <h4 className="text-xs font-bold text-gray-500 uppercase">إضافة مستخدم جديد</h4>
                 <input placeholder="الاسم الكامل" className="w-full p-2 border rounded-lg" value={newUser.fullName} onChange={e => setNewUser({...newUser, fullName: e.target.value})} />
                 <div className="grid grid-cols-2 gap-2">
                     <input placeholder="اسم المستخدم" className="w-full p-2 border rounded-lg" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} />
                     <input type="password" placeholder="كلمة المرور" className="w-full p-2 border rounded-lg" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} />
                 </div>
                 <div className="flex gap-2">
                     <select className="p-2 border rounded-lg bg-white" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value as 'user' | 'admin'})}>
