              <button onClick={handleSaveAsBackup} className="flex-1 bg-purple-50 text-purple-700 border-2 border-purple-100 px-6 py-5 rounded-2xl hover:bg-purple-100 transition-all flex items-center justify-center gap-3 font-bold"><Save size={24} /> حفظ باسم</button>
              <div className="flex-1 relative">
                  <input type="file" accept=".json" ref={fileInputRef} className="hidden" onChange={handleRestore} />
                  <button onClick={() => fileInputRef.current?.click()} className="w-full bg-gray-50 text-gray-600 border-2 border-gray-100 px-6 py-5 rounded-2xl hover:bg-gray-100 transition-all flex items-center justify-center gap-3 font-bold h-full"><Upload size={24} /> استعادة ملف محفوظ</button>
              </div>
          </div>
      </div>
    </div>
  );
};

