                    if (!typedItems || typedItems.length === 0) return null;
                    return (
                        <React.Fragment key={type}>
                            <tr className="bg-primary-50 border-y border-primary-100"><td colSpan={6} className="p-2 px-4 font-bold text-primary-700">{type}</td></tr>
