import CryptoJS from 'crypto-js';

const ACTIVATION_KEY_STORAGE = 'pharmamind_license_key';
const DEVICE_ID_STORAGE = 'pharmamind_device_id';

// هذا هو "الملح" السري الذي يستخدم لتوليد السيريال. لا تشاركه.
// المعادلة: MD5(DeviceID + SECRET_SALT)
const SECRET_SALT = "ABDULLAH_PHARMA_SECURE_2025_PREMIUM";

export const ActivationService = {
  // الحصول على معرف الجهاز (يتم إنشاؤه مرة واحدة)
  getDeviceId: (): string => {
    let deviceId = localStorage.getItem(DEVICE_ID_STORAGE);
    if (!deviceId) {
      // إنشاء معرف عشوائي
      deviceId = 'DEVICE-' + Math.random().toString(36).substring(2, 10).toUpperCase() + 
                 '-' + Date.now().toString(36).toUpperCase();
      localStorage.setItem(DEVICE_ID_STORAGE, deviceId);
    }
    return deviceId;
  },

  // التحقق من حالة التفعيل
  isActivated: (): boolean => {
    const storedKey = localStorage.getItem(ACTIVATION_KEY_STORAGE);
    if (!storedKey) return false;

    const deviceId = ActivationService.getDeviceId();
    const expectedKey = ActivationService.generateExpectedKey(deviceId);

    return storedKey === expectedKey;
  },

  // تفعيل البرنامج
  activate: (inputKey: string): boolean => {
    const deviceId = ActivationService.getDeviceId();
    const expectedKey = ActivationService.generateExpectedKey(deviceId);

    if (inputKey.trim() === expectedKey) {
      localStorage.setItem(ACTIVATION_KEY_STORAGE, inputKey.trim());
      return true;
    }
    return false;
  },

  // (داخلي) توليد الكود الصحيح بناءً على معرف الجهاز
  generateExpectedKey: (deviceId: string): string => {
    // نستخدم MD5 للحصول على كود قصير نسبياً ومميز
    // نأخذ أول 16 حرف فقط ليكون أسهل في التعامل
    return CryptoJS.MD5(deviceId + SECRET_SALT).toString().toUpperCase().substring(0, 16);
  }
};

