import { AppSettings, DEFAULT_SETTINGS, Invoice, CalculatedItem, Supplier, Client, ClientTransaction, ItemCatalogEntry, User, PendingItem } from '../types';
import CryptoJS from 'crypto-js';
import * as XLSX from 'xlsx';
import { Capacitor } from '@capacitor/core';
import { Filesystem, Directory } from '@capacitor/filesystem';
import { Share } from '@capacitor/share';

const KEYS = {
  SETTINGS: 'pharmamind_settings',
  INVOICES: 'pharmamind_invoices',
  SUPPLIERS: 'pharmamind_suppliers',
  CLIENTS: 'pharmamind_clients',
  TRANSACTIONS: 'pharmamind_transactions',
  CATALOG: 'pharmamind_catalog',
  PENDING_ITEMS: 'pharmamind_pending_items',
};

const SECRET_KEY = "PHARMA_MIND_SECURE_7837047136367";

const encrypt = (data: any): string => {
  try {
    return CryptoJS.AES.encrypt(JSON.stringify(data), SECRET_KEY).toString();
  } catch (e) {
    console.error("Encryption Error", e);
    return "";
  }
};

const decrypt = (ciphertext: string | null): any => {
  if (!ciphertext) return null;
  try {
    if (ciphertext.startsWith('[') || ciphertext.startsWith('{')) {
        return JSON.parse(ciphertext);
    }
    const bytes = CryptoJS.AES.decrypt(ciphertext, SECRET_KEY);
    const decryptedData = bytes.toString(CryptoJS.enc.Utf8);
    return decryptedData ? JSON.parse(decryptedData) : null;
  } catch (e) {
    console.error("Decryption Error", e);
    return null;
  }
};

export const StorageService = {
  getSettings: (): AppSettings => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.SETTINGS));
      if (data) {
        if (!data.users || data.users.length === 0) data.users = [DEFAULT_SETTINGS.users[0]];
        return data;
      }
      return DEFAULT_SETTINGS;
    } catch (e) { return DEFAULT_SETTINGS; }
  },

  saveSettings: (settings: AppSettings): void => {
    localStorage.setItem(KEYS.SETTINGS, encrypt(settings));
  },

  getCurrentUser: (): User | null => {
      const userStr = sessionStorage.getItem('current_user');
      return userStr ? JSON.parse(userStr) : null;
  },

  getCatalog: (): ItemCatalogEntry[] => {
      try {
          const data = decrypt(localStorage.getItem(KEYS.CATALOG));
          return data || [];
      } catch { return []; }
  },

  saveCatalogItem: (item: ItemCatalogEntry): void => {
      const list = StorageService.getCatalog();
      const idx = list.findIndex(i => i.id === item.id || i.name.trim().toLowerCase() === item.name.trim().toLowerCase());
      if (idx >= 0) list[idx] = { ...list[idx], ...item }; // Merge to keep ID if updating by name
      else list.push(item);
      localStorage.setItem(KEYS.CATALOG, encrypt(list));
  },

  deleteCatalogItem: (id: string): void => {
      const list = StorageService.getCatalog();
      const updated = list.filter(i => i.id !== id);
      localStorage.setItem(KEYS.CATALOG, encrypt(updated));
  },

  importCatalog: (items: ItemCatalogEntry[]): void => {
      const current = StorageService.getCatalog();
      items.forEach(newItem => {
          const existingIdx = current.findIndex(c => c.name.trim().toLowerCase() === newItem.name.trim().toLowerCase());
          if (existingIdx >= 0) {
              current[existingIdx] = { ...current[existingIdx], ...newItem, id: current[existingIdx].id };
          } else {
              current.push({ ...newItem, id: Date.now().toString() + Math.random() });
          }
      });
      localStorage.setItem(KEYS.CATALOG, encrypt(current));
  },

  getSuppliers: (): Supplier[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.SUPPLIERS));
      return data || [];
    } catch (e) { return []; }
  },

  saveSupplier: (supplier: Supplier): void => {
    const list = StorageService.getSuppliers();
    const existingIndex = list.findIndex(s => s.id === supplier.id);
    if (existingIndex >= 0) {
        list[existingIndex] = supplier;
    } else {
        list.push(supplier);
    }
    localStorage.setItem(KEYS.SUPPLIERS, encrypt(list));
  },

  deleteSupplier: (id: string): void => {
    const list = StorageService.getSuppliers();
    const updated = list.filter(s => s.id !== id);
    localStorage.setItem(KEYS.SUPPLIERS, encrypt(updated));
  },

  // --- Pending Items Logic ---
  getPendingItems: (): PendingItem[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.PENDING_ITEMS));
      return data || [];
    } catch { return []; }
  },

  addPendingItem: (item: PendingItem): void => {
    const list = StorageService.getPendingItems();
    list.push(item);
    localStorage.setItem(KEYS.PENDING_ITEMS, encrypt(list));
  },

  deletePendingItem: (id: string): void => {
    const list = StorageService.getPendingItems();
    const updated = list.filter(i => i.id !== id);
    localStorage.setItem(KEYS.PENDING_ITEMS, encrypt(updated));
  },

  deletePendingItemByNameAndSupplier: (itemName: string, supplierId: string): boolean => {
      const list = StorageService.getPendingItems();
      const initialLen = list.length;
      const updated = list.filter(i => !(i.itemName.trim().toLowerCase() === itemName.trim().toLowerCase() && i.supplierId === supplierId));
      if (updated.length !== initialLen) {
          localStorage.setItem(KEYS.PENDING_ITEMS, encrypt(updated));
          return true; // Deleted successfully
      }
      return false;
  },

  getClients: (): Client[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.CLIENTS));
      return data || [];
    } catch (e) { return []; }
  },

  saveClient: (client: Client): void => {
    const list = StorageService.getClients();
    const existingIndex = list.findIndex(c => c.id === client.id);
    if (existingIndex >= 0) {
        list[existingIndex] = client;
    } else {
        list.push(client);
    }
    localStorage.setItem(KEYS.CLIENTS, encrypt(list));
  },

  deleteClient: (id: string): void => {
    const list = StorageService.getClients();
    const updated = list.filter(c => c.id !== id);
    localStorage.setItem(KEYS.CLIENTS, encrypt(updated));
  },

  getTransactions: (clientId?: string): ClientTransaction[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.TRANSACTIONS));
      const all = data || [];
      if (clientId) {
        return all.filter((t: ClientTransaction) => t.clientId === clientId).sort((a: any, b: any) => new Date(b.date).getTime() - new Date(a.date).getTime());
      }
      return all;
    } catch (e) { return []; }
  },

  addTransaction: (transaction: ClientTransaction): void => {
    const transactions = StorageService.getTransactions();
    transactions.push(transaction);
    localStorage.setItem(KEYS.TRANSACTIONS, encrypt(transactions));

    const clients = StorageService.getClients();
    const clientIndex = clients.findIndex(c => c.id === transaction.clientId);
    if (clientIndex >= 0) {
        const client = clients[clientIndex];
        if (transaction.type === 'SALE') {
            client.balance += transaction.amount;
        } else {
            client.balance -= transaction.amount;
        }
        clients[clientIndex] = client;
        localStorage.setItem(KEYS.CLIENTS, encrypt(clients));
    }
  },

  getInvoices: (): Invoice[] => {
    try {
      const data = decrypt(localStorage.getItem(KEYS.INVOICES));
      return data || [];
    } catch (e) { return []; }
  },

  getInvoiceById: (id: string): Invoice | undefined => {
      return StorageService.getInvoices().find(i => i.id === id);
  },

  saveInvoice: (invoice: Invoice): void => {
    const invoices = StorageService.getInvoices();
    const index = invoices.findIndex(i => i.id === invoice.id);

    if (index >= 0) {
        invoices[index] = invoice;
    } else {
        invoices.unshift(invoice);
    }
    localStorage.setItem(KEYS.INVOICES, encrypt(invoices));

    // Auto-update catalog
    const catalog = StorageService.getCatalog();
    let catalogChanged = false;
    invoice.items.forEach(item => {
        const existingIdx = catalog.findIndex(c => c.name.trim().toLowerCase() === item.name.trim().toLowerCase());
        if (existingIdx === -1) {
            catalog.push({
                id: Date.now().toString() + Math.random(),
                name: item.name,
                type: item.type,
                publicPrice: item.publicPrice,
                pharmaPrice: item.pharmaPrice,
                supplierDiscountVal: item.supplierDiscountVal,
                taxValue: item.taxValue,
                taxMethod: item.taxMethod
            });
            catalogChanged = true;
        } 
    });
    if (catalogChanged) localStorage.setItem(KEYS.CATALOG, encrypt(catalog));
  },

  markInvoiceAsSold: (invoiceId: string, clientId: string): void => {
    const invoices = StorageService.getInvoices();
    const index = invoices.findIndex(inv => inv.id === invoiceId);
    if (index >= 0) {
        invoices[index].isSold = true;
        invoices[index].soldToClientId = clientId;
        invoices[index].soldDate = new Date().toISOString();
        localStorage.setItem(KEYS.INVOICES, encrypt(invoices));
    }
  },

  deleteInvoice: (id: string): void => {
    const invoices = StorageService.getInvoices();
    const updated = invoices.filter(inv => inv.id !== id);
    localStorage.setItem(KEYS.INVOICES, encrypt(updated));
  },

  getLastPurchaseItem: (itemName: string): CalculatedItem | null => {
    const invoices = StorageService.getInvoices();
    for (const inv of invoices) {
      const found = inv.items.find(item => item.name.trim().toLowerCase() === itemName.trim().toLowerCase());
      if (found) return found;
    }
    return null;
  },

  getItemWithBonusHistory: (itemName: string): CalculatedItem | null => {
    const invoices = StorageService.getInvoices();
    for (const inv of invoices) {
      const found = inv.items.find(item => 
        item.name.trim().toLowerCase() === itemName.trim().toLowerCase() && 
        item.bonus > 0
      );
      if (found) return found;
    }
    return null;
  },

  getAllItemNames: (): string[] => {
    const catalogNames = StorageService.getCatalog().map(c => c.name);
    const invoiceNames = new Set<string>();
    StorageService.getInvoices().forEach(inv => {
        inv.items.forEach(item => invoiceNames.add(item.name));
    });
    return Array.from(new Set([...catalogNames, ...Array.from(invoiceNames)]));
  },

  getCatalogItemByName: (name: string): ItemCatalogEntry | undefined => {
      return StorageService.getCatalog().find(c => c.name.trim().toLowerCase() === name.trim().toLowerCase());
  },

  createBackup: (): string => {
      const backup = {
          settings: StorageService.getSettings(),
          suppliers: StorageService.getSuppliers(),
          clients: StorageService.getClients(),
          invoices: StorageService.getInvoices(),
          transactions: StorageService.getTransactions(),
          catalog: StorageService.getCatalog(),
          pending: StorageService.getPendingItems(),
          version: '2.1',
          date: new Date().toISOString()
      };
      return JSON.stringify(backup, null, 2);
  },

  restoreBackup: (jsonString: string): boolean => {
      try {
          if (!jsonString) return false;
          const cleanJson = jsonString.replace(/^\uFEFF/, '');
          const data = JSON.parse(cleanJson);

          if (!data || typeof data !== 'object') {
             console.error("Invalid backup format");
             return false;
          }

          if (data.settings) localStorage.setItem(KEYS.SETTINGS, encrypt(data.settings));
          if (data.suppliers) localStorage.setItem(KEYS.SUPPLIERS, encrypt(data.suppliers));
          if (data.clients) localStorage.setItem(KEYS.CLIENTS, encrypt(data.clients));
          if (data.invoices) localStorage.setItem(KEYS.INVOICES, encrypt(data.invoices));
          if (data.transactions) localStorage.setItem(KEYS.TRANSACTIONS, encrypt(data.transactions));
          if (data.catalog) localStorage.setItem(KEYS.CATALOG, encrypt(data.catalog));
          if (data.pending) localStorage.setItem(KEYS.PENDING_ITEMS, encrypt(data.pending));

          return true;
      } catch (e) {
          console.error("Restore Failed", e);
          return false;
      }
  },

  // ---------------- Excel Export / Import ----------------

  exportBackupToExcel: async (): Promise<boolean> => {
      try {
          // 1. Prepare Data
          const suppliers = StorageService.getSuppliers();
          const clients = StorageService.getClients();
          const catalog = StorageService.getCatalog();
          const pending = StorageService.getPendingItems();
          const transactions = StorageService.getTransactions();
          const invoices = StorageService.getInvoices();
          const settings = StorageService.getSettings();

          // 2. Separate Invoice Headers from Invoice Items for relational structure
          const invoiceHeaders = invoices.map(({ items, ...rest }) => rest);
          const invoiceItems: any[] = [];
          invoices.forEach(inv => {
              inv.items.forEach(item => {
                  invoiceItems.push({
                      invoiceId: inv.id,
                      invoiceDate: inv.date,
                      ...item
                  });
              });
          });

          // 3. Create Workbook
          const wb = XLSX.utils.book_new();

          // 4. Create Sheets
          const sheetSettings = XLSX.utils.json_to_sheet([settings]);
          const sheetSuppliers = XLSX.utils.json_to_sheet(suppliers);
          const sheetClients = XLSX.utils.json_to_sheet(clients);
          const sheetCatalog = XLSX.utils.json_to_sheet(catalog);
          const sheetPending = XLSX.utils.json_to_sheet(pending);
          const sheetTrans = XLSX.utils.json_to_sheet(transactions);
          const sheetInvHeaders = XLSX.utils.json_to_sheet(invoiceHeaders);
          const sheetInvItems = XLSX.utils.json_to_sheet(invoiceItems);

          // 5. Append Sheets
          XLSX.utils.book_append_sheet(wb, sheetSettings, "Settings");
          XLSX.utils.book_append_sheet(wb, sheetSuppliers, "Suppliers");
          XLSX.utils.book_append_sheet(wb, sheetClients, "Clients");
          XLSX.utils.book_append_sheet(wb, sheetCatalog, "Catalog");
          XLSX.utils.book_append_sheet(wb, sheetPending, "PendingItems");
          XLSX.utils.book_append_sheet(wb, sheetTrans, "Transactions");
          XLSX.utils.book_append_sheet(wb, sheetInvHeaders, "Invoices_Data");
          XLSX.utils.book_append_sheet(wb, sheetInvItems, "Invoices_Items");

          const fileName = `PharmaMind_Excel_Backup_${new Date().toISOString().split('T')[0]}.xlsx`;

          // 6. Handle Export based on Platform
          if (Capacitor.isNativePlatform()) {
              // Write to local filesystem then share
              const wbout = XLSX.write(wb, { bookType: 'xlsx', type: 'base64' });

              try {
                const result = await Filesystem.writeFile({
                  path: fileName,
                  data: wbout,
                  directory: Directory.Documents,
                });

                await Share.share({
                  title: 'نسخة احتياطية PharmaMind',
                  text: 'تصدير بيانات صيدليتي الذكية',
                  url: result.uri,
                  dialogTitle: 'مشاركة ملف الإكسل',
                });
                return true;
              } catch (e) {
                console.error("Native write failed", e);
                // Fallback attempt to Cache if Documents failed (permission issues)
                try {
                    const resultCache = await Filesystem.writeFile({
                        path: fileName,
                        data: wbout,
                        directory: Directory.Cache,
                    });
                    await Share.share({
                        title: 'نسخة احتياطية',
                        url: resultCache.uri
                    });
                    return true;
                } catch (innerE) {
                     console.error("Cache write failed", innerE);
                     return false;
                }
              }
          } else {
              // Web Browser
              XLSX.writeFile(wb, fileName);
              return true;
          }
      } catch (e) {
          console.error("Excel Export Error", e);
          return false;
      }
  },

  restoreBackupFromExcel: async (file: File): Promise<boolean> => {
      return new Promise((resolve) => {
          const reader = new FileReader();
          reader.onload = (e) => {
              try {
                  const data = new Uint8Array(e.target?.result as ArrayBuffer);
                  const wb = XLSX.read(data, { type: 'array' });

                  // Helper to safe get sheet
                  const getSheet = (name: string) => {
                      return wb.Sheets[name] ? XLSX.utils.sheet_to_json(wb.Sheets[name]) : [];
                  };

                  // 1. Read Sheets
                  const settingsRaw = getSheet("Settings");
                  const suppliers = getSheet("Suppliers") as Supplier[];
                  const clients = getSheet("Clients") as Client[];
                  const catalog = getSheet("Catalog") as ItemCatalogEntry[];
                  const pending = getSheet("PendingItems") as PendingItem[];
                  const transactions = getSheet("Transactions") as ClientTransaction[];
                  const invHeaders = getSheet("Invoices_Data") as any[];
                  const invItems = getSheet("Invoices_Items") as any[];

                  // 2. Reconstruct Invoices (Join Headers with Items)
                  const reconstructedInvoices: Invoice[] = invHeaders.map(header => {
                      const items = invItems.filter(i => i.invoiceId === header.id).map(({ invoiceId, invoiceDate, ...item }) => item);
                      return {
                          ...header,
                          items: items as CalculatedItem[]
                      };
                  });

                  // 3. Save to Storage (Encrypts automatically)
                  if (settingsRaw.length > 0) localStorage.setItem(KEYS.SETTINGS, encrypt(settingsRaw[0]));
                  localStorage.setItem(KEYS.SUPPLIERS, encrypt(suppliers));
                  localStorage.setItem(KEYS.CLIENTS, encrypt(clients));
                  localStorage.setItem(KEYS.CATALOG, encrypt(catalog));
                  localStorage.setItem(KEYS.PENDING_ITEMS, encrypt(pending));
                  localStorage.setItem(KEYS.TRANSACTIONS, encrypt(transactions));
                  localStorage.setItem(KEYS.INVOICES, encrypt(reconstructedInvoices));

                  resolve(true);
              } catch (err) {
                  console.error("Excel Import Error", err);
                  resolve(false);
              }
          };
          reader.onerror = () => resolve(false);
          reader.readAsArrayBuffer(file);
      });
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Save, RefreshCw, Download, Upload, Database, Check, User, ShieldCheck, Settings2, Image as ImageIcon, Plus, Trash2, FileSpreadsheet, Cloud, Globe, Key } from 'lucide-react';
import { StorageService } from '../services/storageService';
import { AppSettings, DEFAULT_SETTINGS, User as UserType } from '../types';

const Settings: React.FC = () => {
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [msg, setMsg] = useState('');
  const [newUser, setNewUser] = useState<UserType>({ id: '', username: '', password: '', fullName: '', role: 'user', permissions: [] });
  const fileInputRef = useRef<HTMLInputElement>(null);
  const excelInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { setSettings(StorageService.getSettings()); }, []);

  const handleSave = () => {
    StorageService.saveSettings(settings);
    setMsg('تم حفظ الإعدادات بنجاح');
    setTimeout(() => setMsg(''), 3000);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onloadend = () => {
              setSettings(prev => ({ ...prev, userAvatar: reader.result as string }));
          };
          reader.readAsDataURL(file);
      }
  };

  const handleAddUser = () => {
      if (!newUser.username || !newUser.password) return alert('اسم المستخدم وكلمة المرور مطلوبان');
      const updatedUsers = [...settings.users, { ...newUser, id: Date.now().toString(), permissions: newUser.role === 'admin' ? ['*'] : newUser.permissions }];
      setSettings(prev => ({ ...prev, users: updatedUsers }));
      setNewUser({ id: '', username: '', password: '', fullName: '', role: 'user', permissions: [] });
  };

  const handleRemoveUser = (userId: string) => {
      if (settings.users.length <= 1) return alert('لا يمكن حذف المستخدم الوحيد');
      setSettings(prev => ({ ...prev, users: prev.users.filter(u => u.id !== userId) }));
  };

  const handleQuickBackup = () => {
      const data = StorageService.createBackup();
      const fileName = `pharmamind_backup_${new Date().toISOString().split('T')[0]}.json`;
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = fileName;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      setMsg('تم تحميل النسخة بنجاح');
      setTimeout(() => setMsg(''), 3000);
  };

  const handleExportExcel = async () => {
      const success = await StorageService.exportBackupToExcel();
      if (success) {
          setMsg('تم تجهيز ملف Excel للمشاركة');
      } else {
          alert('حدث خطأ أثناء التصدير');
      }
      setTimeout(() => setMsg(''), 3000);
  };

  const handleImportExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      if (confirm('تحذير: استيراد ملف Excel سيقوم باستبدال البيانات الحالية. هل أنت متأكد؟')) {
          const success = await StorageService.restoreBackupFromExcel(file);
          if (success) {
              alert('تم استعادة البيانات بنجاح! سيتم إعادة تحميل التطبيق.');
              window.location.reload();
          } else {
              alert('فشل استيراد الملف. تأكد من صحة الملف وتنسيقه.');
          }
      }
      e.target.value = ''; // Reset input
  };

  const handleRestore = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
          const content = event.target?.result as string;
          if (StorageService.restoreBackup(content)) {
              setMsg('تم استعادة البيانات! جاري إعادة التحميل...');
              setTimeout(() => window.location.reload(), 2000);
          } else {
              alert('فشل استعادة الملف.');
          }
      };
      reader.readAsText(file);
      e.target.value = '';
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-8">
        <h2 className="text-2xl font-bold mb-8 text-gray-800 flex items-center gap-2"><Settings2 className="text-primary-600" /> إعدادات النظام والأمان</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-4">
             <h3 className="font-bold text-gray-700 flex items-center gap-2 border-b pb-2"><User size={18} className="text-blue-500" /> مظهر التطبيق</h3>
             <div><label className="block text-xs font-bold text-gray-500 mb-1">اسم الصيدلية</label><input type="text" value={settings.pharmacyName} onChange={(e) => setSettings({...settings, pharmacyName: e.target.value})} className="w-full p-3 border rounded-xl" /></div>
             <div><label className="block text-xs font-bold text-gray-500 mb-1">نص اللوجو (شاشة الدخول)</label><input type="text" value={settings.logoText || ''} onChange={(e) => setSettings({...settings, logoText: e.target.value})} className="w-full p-3 border rounded-xl" placeholder="PharmaMind" /></div>

             <div>
                <label className="block text-xs font-bold text-gray-500 mb-2">شعار / صورة الملف الشخصي</label>
                <div className="flex items-center gap-4">
                    <div className="w-16 h-16 rounded-full bg-gray-100 border overflow-hidden">
                        {settings.userAvatar ? <img src={settings.userAvatar} className="w-full h-full object-cover" /> : <User className="w-full h-full p-4 text-gray-300" />}
                    </div>
                    <input type="file" ref={imageInputRef} accept="image/*" className="hidden" onChange={handleImageUpload} />
                    <button onClick={() => imageInputRef.current?.click()} className="text-sm bg-gray-50 border px-3 py-2 rounded-lg hover:bg-gray-100 flex items-center gap-1"><ImageIcon size={14} /> اختر صورة</button>
                    {settings.userAvatar && <button onClick={() => setSettings({...settings, userAvatar: undefined})} className="text-sm text-red-500 hover:text-red-700">حذف</button>}
                </div>
             </div>
          </div>

          <div className="space-y-4">
             <h3 className="font-bold text-gray-700 flex items-center gap-2 border-b pb-2"><ShieldCheck size={18} className="text-green-500" /> إدارة المستخدمين</h3>

             <div className="bg-gray-50 p-4 rounded-xl space-y-3 border border-gray-200">
                 <h4 className="text-xs font-bold text-gray-500 uppercase">إضافة مستخدم جديد</h4>
                 <input placeholder="الاسم الكامل" className="w-full p-2 border rounded-lg" value={newUser.fullName} onChange={e => setNewUser({...newUser, fullName: e.target.value})} />
                 <div className="grid grid-cols-2 gap-2">
                     <input placeholder="اسم المستخدم" className="w-full p-2 border rounded-lg" value={newUser.username} onChange={e => setNewUser({...newUser, username: e.target.value})} />
                     <input type="password" placeholder="كلمة المرور" className="w-full p-2 border rounded-lg" value={newUser.password} onChange={e => setNewUser({...newUser, password: e.target.value})} />
                 </div>
                 <div className="flex gap-2">
                     <select className="p-2 border rounded-lg bg-white" value={newUser.role} onChange={e => setNewUser({...newUser, role: e.target.value as 'user' | 'admin'})}>
                         <option value="user">مستخدم عادي</option>
                         <option value="admin">مسؤول كامل</option>
                     </select>
                     <button onClick={handleAddUser} className="flex-1 bg-green-600 text-white rounded-lg font-bold flex items-center justify-center gap-1"><Plus size={16} /> إضافة</button>
                 </div>
             </div>

             <div className="space-y-2 max-h-40 overflow-y-auto">
                 {settings.users?.map(user => (
                     <div key={user.id} className="flex justify-between items-center p-3 bg-white border rounded-lg">
                         <div>
                             <div className="font-bold text-sm">{user.username}</div>
                             <div className="text-xs text-gray-400">{user.role === 'admin' ? 'Admin' : 'User'}</div>
                         </div>
                         <button onClick={() => handleRemoveUser(user.id)} className="text-red-500 hover:bg-red-50 p-1.5 rounded"><Trash2 size={16} /></button>
                     </div>
                 ))}
             </div>
          </div>
        </div>

        {/* Cloud Sync Section */}
        <div className="mt-10 pt-10 border-t space-y-6">
             <h3 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                <Cloud className="text-indigo-600" /> الربط السحابي والمشاركة (Beta)
             </h3>
             <p className="text-sm text-gray-500 bg-indigo-50 p-4 rounded-xl border border-indigo-100">
                تفعيل هذا الخيار يسمح بربط عدة أجهزة معاً لمشاركة نفس قاعدة البيانات. ملاحظة: هذا يتطلب وجود خادم (Server) خاص بك لحفظ البيانات.
             </p>

             <div className="flex items-center gap-4 p-4 bg-white border-2 border-gray-100 rounded-2xl">
                 <div className="flex-1">
                     <div className="font-bold text-gray-800">تفعيل وضع المشاركة</div>
                     <div className="text-xs text-gray-400">عند التفعيل، سيتوقف التطبيق عن الاعتماد على الذاكرة المحلية فقط وسيبدأ بالمزامنة.</div>
                 </div>
                 <button 
                    onClick={() => setSettings({...settings, cloudConfig: {...(settings.cloudConfig || DEFAULT_SETTINGS.cloudConfig!), enabled: !settings.cloudConfig?.enabled}})}
                    className={`w-14 h-8 rounded-full transition-all relative ${settings.cloudConfig?.enabled ? 'bg-green-500' : 'bg-gray-200'}`}
                 >
                     <div className={`absolute top-1 w-6 h-6 bg-white rounded-full transition-all ${settings.cloudConfig?.enabled ? 'left-7' : 'left-1'}`} />
                 </button>
             </div>

             {settings.cloudConfig?.enabled && (
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fade-in">
                     <div>
                        <label className="block text-xs font-bold text-gray-500 mb-1 flex items-center gap-1"><Globe size={12} /> رابط السيرفر (API Endpoint)</label>
                        <input 
                            type="text" 
                            className="w-full p-3 border rounded-xl" 
                            placeholder="https://your-api.com" 
                            value={settings.cloudConfig.serverUrl}
                            onChange={e => setSettings({...settings, cloudConfig: {...settings.cloudConfig!, serverUrl: e.target.value}})}
                        />
                     </div>
                     <div>
                        <label className="block text-xs font-bold text-gray-500 mb-1 flex items-center gap-1"><Key size={12} /> معرف المجموعة (Group ID)</label>
                        <input 
                            type="text" 
                            className="w-full p-3 border rounded-xl" 
                            placeholder="PHARMA-GROUP-001" 
                            value={settings.cloudConfig.groupId}
                            onChange={e => setSettings({...settings, cloudConfig: {...settings.cloudConfig!, groupId: e.target.value}})}
                        />
                     </div>
                 </div>
             )}
        </div>

        <div className="mt-10 flex items-center justify-between border-t pt-6">
            <button onClick={() => { if(window.confirm('استعادة الإعدادات الافتراضية؟')) { setSettings(DEFAULT_SETTINGS); StorageService.saveSettings(DEFAULT_SETTINGS); } }} className="text-red-500 text-sm font-bold flex items-center gap-1 hover:bg-red-50 p-2 rounded-lg"><RefreshCw size={16} /> استعادة الإعدادات</button>
            <button onClick={handleSave} className="bg-primary-600 text-white px-10 py-4 rounded-2xl shadow-xl shadow-primary-500/30 font-bold flex items-center gap-2"><Save /> حفظ التعديلات</button>
        </div>
        {msg && <div className="mt-4 p-3 bg-green-50 text-green-700 rounded-xl text-center text-sm font-bold flex items-center justify-center gap-2"><Check size={16} /> {msg}</div>}
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-8">
          <h3 className="text-xl font-bold mb-4 text-gray-800 flex items-center gap-2"><Database className="text-purple-600" /> إدارة البيانات والنسخ الاحتياطي</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <button onClick={handleQuickBackup} className="bg-blue-50 text-blue-700 border border-blue-100 px-4 py-6 rounded-2xl hover:bg-blue-100 transition-all flex flex-col items-center justify-center gap-2 font-bold text-sm"><Download size={24} /> تحميل نسخة JSON</button>
              <div className="relative h-full">
                  <input type="file" accept=".json" ref={fileInputRef} className="hidden" onChange={handleRestore} />
                  <button onClick={() => fileInputRef.current?.click()} className="w-full bg-gray-50 text-gray-600 border border-gray-200 px-4 py-6 rounded-2xl hover:bg-gray-100 transition-all flex flex-col items-center justify-center gap-2 font-bold text-sm h-full"><Upload size={24} /> استعادة JSON</button>
              </div>
              <button onClick={handleExportExcel} className="bg-green-50 text-green-700 border border-green-100 px-4 py-6 rounded-2xl hover:bg-green-100 transition-all flex flex-col items-center justify-center gap-2 font-bold text-sm"><FileSpreadsheet size={24} /> تصدير Excel</button>
              <div className="relative h-full">
                  <input type="file" accept=".xlsx, .xls" ref={excelInputRef} className="hidden" onChange={handleImportExcel} />
                  <button onClick={() => excelInputRef.current?.click()} className="w-full bg-gray-50 text-gray-600 border border-gray-200 px-4 py-6 rounded-2xl hover:bg-gray-100 transition-all flex flex-col items-center justify-center gap-2 font-bold text-sm h-full"><Upload size={24} /> استيراد Excel</button>
              </div>
          </div>
      </div>
    </div>
  );
};

